/**
 * Protected Route Component
 * 
 * Provides route protection based on authentication status and user roles.
 * Redirects unauthenticated users to login page.
 */

import React from 'react'
import { useAuth } from '../hooks/useAuth'

interface ProtectedRouteProps {
  children: React.ReactNode
  requiredRole?: 'customer' | 'vendor' | 'admin'
  fallback?: React.ReactNode
}

export function ProtectedRoute({ 
  children, 
  requiredRole, 
  fallback 
}: ProtectedRouteProps) {
  const { isAuthenticated, loading, user } = useAuth()

  // Show loading state while checking authentication
  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    )
  }

  // Check if user is authenticated
  if (!isAuthenticated) {
    if (fallback) {
      return <>{fallback}</>
    }

    // Redirect to login page (in a real app, you'd use React Router)
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <h2 className="text-2xl font-bold mb-4">Authentication Required</h2>
          <p className="text-gray-600 mb-6">Please log in to access this page.</p>
          <button 
            onClick={() => window.location.href = '/login'}
            className="bg-primary text-white px-6 py-2 rounded-md hover:bg-primary/90"
          >
            Go to Login
          </button>
        </div>
      </div>
    )
  }

  // Check if user has required role
  if (requiredRole && user?.role !== requiredRole) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <h2 className="text-2xl font-bold mb-4">Access Denied</h2>
          <p className="text-gray-600 mb-6">
            You don't have permission to access this page.
          </p>
          <button 
            onClick={() => window.history.back()}
            className="bg-secondary text-secondary-foreground px-6 py-2 rounded-md hover:bg-secondary/90"
          >
            Go Back
          </button>
        </div>
      </div>
    )
  }

  // User is authenticated and has required role
  return <>{children}</>
}

/**
 * Authentication Context
 * 
 * Provides authentication state to the entire application.
 * Handles token storage, user session management, and auto-refresh.
 */

import type { ReactNode } from 'react';
import React, { createContext, useContext, useReducer, useEffect, useCallback } from 'react'
import type { User } from '../types'

// ========================================
// Types & Interfaces
// ========================================

export interface AuthState {
  user: User | null
  isAuthenticated: boolean
  loading: boolean
  error: string | null
  accessToken: string | null
  refreshToken: string | null
}

export interface AuthContextType {
  user: User | null
  isAuthenticated: boolean
  loading: boolean
  error: string | null
  accessToken: string | null
  refreshToken: string | null
  login: (user: User, accessToken: string, refreshToken: string) => Promise<void>
  logout: () => Promise<void>
  refreshAccessToken: () => Promise<void>
  clearError: () => void
}

export type AuthAction =
  | { type: 'LOGIN_START' }
  | { type: 'LOGIN_SUCCESS'; payload: { user: User; accessToken: string; refreshToken: string } }
  | { type: 'LOGIN_FAILURE'; payload: { error: string } }
  | { type: 'LOGOUT' }
  | { type: 'REFRESH_TOKEN'; payload: { accessToken: string; refreshToken: string } }
  | { type: 'CLEAR_ERROR' }

// ========================================
// Initial State
// ========================================

const initialState: AuthState = {
  user: null,
  isAuthenticated: false,
  loading: true,
  error: null,
  accessToken: null,
  refreshToken: null
}

// ========================================
// Auth Reducer
// ========================================

function authReducer(state: AuthState, action: AuthAction): AuthState {
  switch (action.type) {
    case 'LOGIN_START': {
      return {
        ...state,
        loading: true,
        error: null
      }
    }

    case 'LOGIN_SUCCESS': {
      return {
        ...state,
        user: action.payload.user,
        isAuthenticated: true,
        loading: false,
        error: null,
        accessToken: action.payload.accessToken,
        refreshToken: action.payload.refreshToken
      }
    }

    case 'LOGIN_FAILURE': {
      return {
        ...state,
        user: null,
        isAuthenticated: false,
        loading: false,
        error: action.payload.error,
        accessToken: null,
        refreshToken: null
      }
    }

    case 'LOGOUT': {
      return {
        ...state,
        user: null,
        isAuthenticated: false,
        loading: false,
        error: null,
        accessToken: null,
        refreshToken: null
      }
    }

    case 'REFRESH_TOKEN': {
      return {
        ...state,
        accessToken: action.payload.accessToken,
        refreshToken: action.payload.refreshToken
      }
    }

    case 'CLEAR_ERROR': {
      return {
        ...state,
        error: null
      }
    }

    default: {
      return state
    }
  }
}

// ========================================
// Auth Context
// ========================================

const AuthContextContext = createContext<AuthContextType | undefined>(undefined)

export function useAuthContext() {
  const context = useContext(AuthContextContext)
  if (context === undefined) {
    throw new Error('useAuthContext must be used within an AuthProvider')
  }
  return context
}

// ========================================
// Auth Provider Component
// ========================================

interface AuthProviderProps {
  children: ReactNode
}

export function AuthProvider({ children }: AuthProviderProps) {
  const [state, dispatch] = useReducer(authReducer, initialState)

  // ========================================
  // Token Storage Utilities
  // ========================================

  const storeTokens = useCallback(async (accessToken: string, refreshToken: string) => {
    try {
      localStorage.setItem('accessToken', accessToken)
      localStorage.setItem('refreshToken', refreshToken)
    } catch (error) {
      console.error('Failed to store tokens:', error)
    }
  }, [])

  const clearTokens = useCallback(() => {
    try {
      localStorage.removeItem('accessToken')
      localStorage.removeItem('refreshToken')
    } catch (error) {
      console.error('Failed to clear tokens:', error)
    }
  }, [])

  const getStoredTokens = useCallback(() => {
    try {
      const accessToken = localStorage.getItem('accessToken')
      const refreshToken = localStorage.getItem('refreshToken')
      return { accessToken, refreshToken }
    } catch (error) {
      console.error('Failed to get stored tokens:', error)
      return { accessToken: null, refreshToken: null }
    }
  }, [])

  // ========================================
  // Login Function
  // ========================================

  const login = useCallback(async (user: User, accessToken: string, refreshToken: string) => {
    dispatch({ type: 'LOGIN_START' })

    try {
      await storeTokens(accessToken, refreshToken)

      dispatch({
        type: 'LOGIN_SUCCESS',
        payload: { user, accessToken, refreshToken }
      })
    } catch (error) {
      dispatch({
        type: 'LOGIN_FAILURE',
        payload: { error: error instanceof Error ? error.message : 'Login failed' }
      })
      throw error
    }
  }, [storeTokens])

  // ========================================
  // Logout Function
  // ========================================

  const logout = useCallback(async () => {
    try {
      // Call logout endpoint to invalidate session
      const { accessToken } = getStoredTokens()
      if (accessToken) {
        await fetch('/auth/v1/logout', {
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${accessToken}`,
            'Content-Type': 'application/json'
          }
        })
      }
    } catch (error) {
      console.error('Logout API call failed:', error)
    } finally {
      clearTokens()
      dispatch({ type: 'LOGOUT' })
    }
  }, [getStoredTokens, clearTokens])

  // ========================================
  // Token Refresh Function
  // ========================================

  const refreshToken = useCallback(async () => {
    const { refreshToken: storedRefreshToken } = getStoredTokens()

    if (!storedRefreshToken) {
      throw new Error('No refresh token available')
    }

    try {
      const response = await fetch('/auth/v1/refresh', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ refreshToken: storedRefreshToken }),
      })

      const data = await response.json()

      if (!response.ok) {
        throw new Error(data.message || 'Token refresh failed')
      }

      await storeTokens(data.accessToken, data.refreshToken)

      dispatch({
        type: 'REFRESH_TOKEN',
        payload: { accessToken: data.accessToken, refreshToken: data.refreshToken }
      })
    } catch (error) {
      console.error('Token refresh failed:', error)
      // Clear tokens and logout on refresh failure
      clearTokens()
      dispatch({ type: 'LOGOUT' })
      throw error
    }
  }, [getStoredTokens, storeTokens, clearTokens])

  // ========================================
  // Clear Error Function
  // ========================================

  const clearError = useCallback(() => {
    dispatch({ type: 'CLEAR_ERROR' })
  }, [])

  // ========================================
  // Initialize Auth State
  // ========================================

  useEffect(() => {
    const initializeAuth = async () => {
      let authResolved = false
      const { accessToken, refreshToken: storedRefreshToken } = getStoredTokens()

      if (!accessToken || !storedRefreshToken) {
        dispatch({ type: 'LOGIN_FAILURE', payload: { error: 'No tokens found' } })
        authResolved = true
        return
      }

      try {
        // Validate current access token
        const response = await fetch('/auth/v1/me', {
          headers: {
            'Authorization': `Bearer ${accessToken}`,
            'Content-Type': 'application/json'
          }
        })

        if (response.ok) {
          const data = await response.json()
          dispatch({
            type: 'LOGIN_SUCCESS',
            payload: {
              user: data.user,
              accessToken,
              refreshToken: storedRefreshToken
            }
          })
          authResolved = true
        } else {
          // Access token invalid, try refresh
          await refreshToken()
          authResolved = true
        }
      } catch (error) {
        console.error('Auth initialization failed:', error)
        dispatch({ type: 'LOGIN_FAILURE', payload: { error: 'Session expired' } })
        authResolved = true
      } finally {
        // Guarantee auth loading terminates on every async path.
        if (!authResolved) {
          dispatch({ type: 'LOGIN_FAILURE', payload: { error: 'Session initialization failed' } })
        }
      }
    }

    initializeAuth()
  }, [getStoredTokens, refreshToken])

  // ========================================
  // Context Value
  // ========================================

  const contextValue: AuthContextType = {
    ...state,
    login,
    logout,
    refreshAccessToken: refreshToken,
    clearError
  }

  return (
    <AuthContextContext.Provider value={contextValue}>
      {children}
    </AuthContextContext.Provider>
  )
}

// ========================================
// Export Context
// ========================================

export const AuthContext = AuthContextContext

/**
 * Authentication Hook
 * 
 * Provides centralized authentication state management for the entire application.
 * Handles login, logout, token refresh, and user session persistence.
 */

import { useCallback, useEffect, useContext, useState } from 'react'
import { AuthContext } from '../context/AuthContext'
import type { LoginCredentials } from '../types'

export interface UseAuthProps {
  onSuccess?: () => void
  onError?: (error: string) => void
}

export function useAuth({ onSuccess, onError }: UseAuthProps = {}) {
  const authContext = useContext(AuthContext)

  if (!authContext) {
    throw new Error('useAuth must be used within an AuthProvider')
  }

  const {
    user,
    isAuthenticated,
    loading,
    error,
    login: contextLogin,
    logout: contextLogout,
    refreshAccessToken: contextRefreshToken
  } = authContext

  // ========================================
  // State Management
  // ========================================

  const [isLoggingIn, setIsLoggingIn] = useState(false)
  const [isSigningUp, setIsSigningUp] = useState(false)
  const [loginError, setLoginError] = useState<string | null>(null)
  const [signupError, setSignupError] = useState<string | null>(null)

  // ========================================
  // Login Function
  // ========================================

  const login = useCallback(async (credentials: LoginCredentials) => {
    setIsLoggingIn(true)
    setLoginError(null)
    try {
      const response = await fetch('/auth/v1/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(credentials),
      })

      const data = await response.json()

      if (!response.ok) {
        throw new Error(data.message || 'Login failed')
      }

      // Store tokens and user data
      await contextLogin(data.user, data.accessToken, data.refreshToken)

      onSuccess?.()
      return data
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : 'Login failed'
      setLoginError(errorMessage)
      onError?.(errorMessage)
      throw error
    } finally {
      setIsLoggingIn(false)
    }
  }, [contextLogin, onSuccess, onError])

  // ========================================
  // Signup Function
  // ========================================

  const signup = useCallback(async (credentials: LoginCredentials) => {
    setIsSigningUp(true)
    setSignupError(null)
    try {
      const response = await fetch('/auth/v1/signup', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(credentials),
      })

      const data = await response.json()

      if (!response.ok) {
        throw new Error(data.message || 'Signup failed')
      }

      // Store tokens and user data
      await contextLogin(data.user, data.accessToken, data.refreshToken)

      onSuccess?.()
      return data
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : 'Signup failed'
      setSignupError(errorMessage)
      onError?.(errorMessage)
      throw error
    } finally {
      setIsSigningUp(false)
    }
  }, [contextLogin, onSuccess, onError])

  // ========================================
  // Logout Function
  // ========================================

  const logout = useCallback(async () => {
    try {
      await contextLogout()
    } catch (error) {
      console.error('Logout error:', error)
    }
  }, [contextLogout])

  // ========================================
  // Token Refresh Function
  // ========================================

  const refreshToken = useCallback(async () => {
    try {
      await contextRefreshToken()
    } catch (error) {
      console.error('Token refresh error:', error)
      // If refresh fails, logout the user
      await logout()
    }
  }, [contextRefreshToken, logout])

  // ========================================
  // Auto-refresh Token
  // ========================================

  useEffect(() => {
    if (!isAuthenticated) return

    // Set up token refresh timer (14 minutes - 1 minute before expiry)
    const refreshInterval = setInterval(() => {
      refreshToken()
    }, 14 * 60 * 1000)

    return () => clearInterval(refreshInterval)
  }, [isAuthenticated, refreshToken])

  // ========================================
  // Computed Values
  // ========================================

  const isCustomer = user?.role === 'customer'
  const isVendor = user?.role === 'vendor'
  const isAdmin = user?.role === 'admin'

  return {
    // State
    user,
    isAuthenticated,
    loading,
    error,
    isLoggingIn,
    isSigningUp,
    loginError,
    signupError,

    // Computed values
    isCustomer,
    isVendor,
    isAdmin,

    // Actions
    login,
    signup,
    logout,
    refreshToken
  }
}

