/**
 * Bundle Management Hook
 * High-performance implementation with cached calculations and memoized operations
 */
import { useCallback, useMemo } from 'react'
import { useQueryClient } from '@tanstack/react-query'
import { 
  useBundles, 
  useCreateBundle, 
  useUpdateBundle, 
  useDeleteBundle 
} from '@shared/hooks/generated'
import { formDataToCreateInput, formDataToUpdateInput } from '../types/bundle.types'
import type { Bundle, CreateBundleInput } from '@api/types'
import type { BundleFormData, BundleManagementOptions } from '../types/bundle.types'

// Type alias for update operations (uses same structure as create)
type UpdateBundleInput = Partial<CreateBundleInput>

export function useBundleManagement(options: BundleManagementOptions = {}) {
  const { storeId, isActive = true } = options
  const queryClient = useQueryClient()

  // Direct SDK hooks
  const bundlesQuery = useBundles({ storeId, isActive })
  const createBundleMutation = useCreateBundle()
  const updateBundleMutation = useUpdateBundle()
  const deleteBundleMutation = useDeleteBundle()

  // Memoized bundle data with computed fields
  const bundleData = useMemo(() => {
    const bundles = bundlesQuery.data || []

    // Single-pass: partition + id index for O(1) lookup by id
    let activeCount = 0
    let inactiveCount = 0
    const activeBundles: Bundle[] = []
    const inactiveBundles: Bundle[] = []
    const bundleById = new Map<string, Bundle>()

    for (const bundle of bundles) {
      bundleById.set(bundle.id, bundle)
      if (bundle.isActive) {
        activeCount++
        activeBundles.push(bundle)
      } else {
        inactiveCount++
        inactiveBundles.push(bundle)
      }
    }

    return {
      bundles,
      bundleById,
      activeBundles,
      inactiveBundles,
      activeCount,
      inactiveCount
    }
  }, [bundlesQuery.data])

  // Memoized create handler with error handling
  const createBundle = useCallback(async (formData: BundleFormData) => {
    if (!storeId) throw new Error('Store ID is required')

    const input = formDataToCreateInput(formData, storeId)
    return createBundleMutation.mutateAsync(input, {
      onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: ['bundles'] })
      }
    })
  }, [storeId, createBundleMutation, queryClient])

  // Memoized update handler
  const updateBundle = useCallback(async (id: string, formData: Partial<BundleFormData>) => {
    const input = formDataToUpdateInput(formData)
    return updateBundleMutation.mutateAsync({ id, input: input }, {
      onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: ['bundles'] })
        queryClient.invalidateQueries({ queryKey: ['bundle', id] })
      }
    })
  }, [updateBundleMutation, queryClient])

  // Memoized delete handler
  const deleteBundle = useCallback(async (id: string) => {
    return deleteBundleMutation.mutateAsync(id, {
      onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: ['bundles'] })
        queryClient.removeQueries({ queryKey: ['bundle', id] })
      }
    })
  }, [deleteBundleMutation, queryClient])

  // Memoized toggle handler
  const toggleBundleStatus = useCallback(async (id: string, isActive: boolean) => {
    return updateBundle(id, { isActive })
  }, [updateBundle])

  // Memoized bundle finder (Map-backed)
  const findBundle = useCallback(
    (id: string) => bundleData.bundleById.get(id),
    [bundleData.bundleById],
  )

  // Memoized bundle search
  const searchBundles = useCallback((searchTerm: string) => {
    if (!searchTerm) return bundleData.bundles

    const searchLower = searchTerm.toLowerCase()
    return bundleData.bundles.filter(bundle => 
      bundle.name.toLowerCase().includes(searchLower) ||
      bundle.description?.toLowerCase().includes(searchLower)
    )
  }, [bundleData.bundles])

  // Memoized bundle filter
  const filterBundles = useCallback((
    searchTerm: string, 
    statusFilter: 'all' | 'active' | 'inactive'
  ) => {
    let filtered = bundleData.bundles

    // Apply status filter first (most selective)
    if (statusFilter !== 'all') {
      filtered = statusFilter === 'active' ? bundleData.activeBundles : bundleData.inactiveBundles
    }

    // Apply search filter
    if (searchTerm) {
      const searchLower = searchTerm.toLowerCase()
      filtered = filtered.filter(bundle => 
        bundle.name.toLowerCase().includes(searchLower) ||
        bundle.description?.toLowerCase().includes(searchLower)
      )
    }

    return filtered
  }, [bundleData.bundles, bundleData.activeBundles, bundleData.inactiveBundles])

  return {
    // Data
    bundles: bundleData.bundles,
    activeBundles: bundleData.activeBundles,
    inactiveBundles: bundleData.inactiveBundles,
    activeCount: bundleData.activeCount,
    inactiveCount: bundleData.inactiveCount,

    // Query state
    isLoading: bundlesQuery.isLoading,
    error: bundlesQuery.error,
    refetch: bundlesQuery.refetch,

    // Actions
    createBundle,
    updateBundle,
    deleteBundle,
    toggleBundleStatus,

    // Utilities
    findBundle,
    searchBundles,
    filterBundles,

    // Loading states
    isCreating: createBundleMutation.isPending,
    isUpdating: updateBundleMutation.isPending,
    isDeleting: deleteBundleMutation.isPending,

    // Type transformers
    formDataToCreateInput,
    formDataToUpdateInput
  }
}

/**
 * Bundle Pricing Hook
 * Handles bundle pricing calculations and validation
 */
import { useMemo, useCallback } from 'react'
import type { Bundle, ItemResponse } from '@api/types'

export interface BundlePricingResult {
  individualTotal: number
  bundlePrice: number
  savings: number
  savingsPercent: number
  isValid: boolean
  errors: string[]
}

export interface BundlePricingOptions {
  bundle: Bundle
  items: ItemResponse[]
}

function itemByIdMap(items: ItemResponse[]): Map<string, ItemResponse> {
  const map = new Map<string, ItemResponse>()
  for (const item of items) {
    map.set(item.id, item)
  }
  return map
}

export function useBundlePricing({ bundle, items }: BundlePricingOptions) {
  const pricing = useMemo(() => {
    const errors: string[] = []
    const safeItems = items ?? []

    // Early return if no items provided - avoid expensive calculations
    if (safeItems.length === 0) {
      return {
        individualTotal: 0,
        bundlePrice: bundle.pricing?.fixedPrice || 0,
        savings: 0,
        savingsPercent: 0,
        isValid: true,
        errors: []
      }
    }

    const byId = itemByIdMap(safeItems)

    // Calculate individual item total (O(bundle lines) lookups via Map)
    const individualTotal = bundle.items?.reduce((sum, bundleItem) => {
      const item = byId.get(bundleItem.itemId)
      if (!item) {
        errors.push(`Item ${bundleItem.itemId} not found`)
        return sum
      }
      return sum + (Number(item.price) * bundleItem.quantity)
    }, 0) || 0

    // Calculate bundle price based on pricing type
    let bundlePrice = individualTotal

    if (bundle.pricing?.pricingType === 'FIXED_PRICE' && bundle.pricing.fixedPrice) {
      bundlePrice = bundle.pricing.fixedPrice
    } else if (bundle.pricing?.pricingType === 'DISCOUNT_PERCENT' && bundle.pricing.discountPercent) {
      const discount = (individualTotal * bundle.pricing.discountPercent) / 100
      bundlePrice = Math.max(0, individualTotal - discount)
    } else if (bundle.pricing?.pricingType === 'DISCOUNT_AMOUNT' && bundle.pricing.discountAmount) {
      bundlePrice = Math.max(0, individualTotal - bundle.pricing.discountAmount)
    }

    // Calculate savings
    const savings = Math.max(0, individualTotal - bundlePrice)
    const savingsPercent = individualTotal > 0 ? (savings / individualTotal) * 100 : 0

    // Validate pricing
    if (bundlePrice <= 0) {
      errors.push('Bundle price must be greater than 0')
    }

    if (bundlePrice > individualTotal) {
      errors.push('Bundle price cannot be higher than individual item total')
    }

    // Check minimum savings if specified
    if (bundle.pricing?.minSavings && savings < bundle.pricing.minSavings) {
      errors.push(`Savings must be at least $${bundle.pricing.minSavings}`)
    }

    return {
      individualTotal,
      bundlePrice,
      savings,
      savingsPercent,
      isValid: errors.length === 0,
      errors
    }
  }, [bundle, items])

  // Calculate pricing for a specific set of items
  const calculatePricingForItems = useCallback((items: ItemResponse[], quantities: Record<string, number>) => {
    const individualTotal = items.reduce((sum, item) => {
      const quantity = quantities[item.id] || 0
      return sum + (Number(item.price) * quantity)
    }, 0)

    return {
      individualTotal,
      itemCount: items.length,
      totalQuantity: Object.values(quantities).reduce((sum, qty) => sum + qty, 0)
    }
  }, [])

  // Get pricing recommendations
  const getPricingRecommendations = useCallback(() => {
    const { individualTotal, bundlePrice, savings } = pricing

    const recommendations = []

    if (savings > 0) {
      recommendations.push({
        type: 'savings' as const,
        message: `Save $${savings.toFixed(2)} (${pricing.savingsPercent.toFixed(1)}%)`,
        value: savings
      })
    }

    if (bundlePrice < individualTotal * 0.8) {
      recommendations.push({
        type: 'discount' as const,
        message: 'Great discount! Consider increasing price slightly',
        value: bundlePrice
      })
    }

    return recommendations
  }, [pricing])

  return {
    pricing,
    calculatePricingForItems,
    getPricingRecommendations
  }
}

// Helper function for pricing calculations
export const calculateBundlePricing = (
  bundle: Bundle, 
  items: ItemResponse[]
): BundlePricingResult => {
  const byId = itemByIdMap(items ?? [])
  const individualTotal = bundle.items?.reduce((sum, bundleItem) => {
    const item = byId.get(bundleItem.itemId)
    return sum + (Number(item?.price || 0) * bundleItem.quantity)
  }, 0) || 0

  let bundlePrice = individualTotal

  if (bundle.pricing?.pricingType === 'FIXED_PRICE' && bundle.pricing.fixedPrice) {
    bundlePrice = bundle.pricing.fixedPrice
  } else if (bundle.pricing?.pricingType === 'DISCOUNT_PERCENT' && bundle.pricing.discountPercent) {
    const discount = (individualTotal * bundle.pricing.discountPercent) / 100
    bundlePrice = Math.max(0, individualTotal - discount)
  } else if (bundle.pricing?.pricingType === 'DISCOUNT_AMOUNT' && bundle.pricing.discountAmount) {
    bundlePrice = Math.max(0, individualTotal - bundle.pricing.discountAmount)
  }

  const savings = Math.max(0, individualTotal - bundlePrice)
  const savingsPercent = individualTotal > 0 ? (savings / individualTotal) * 100 : 0

  return {
    individualTotal,
    bundlePrice,
    savings,
    savingsPercent,
    isValid: bundlePrice > 0 && bundlePrice <= individualTotal,
    errors: []
  }
}

/**
 * Bundle Types
 * Frontend-specific types for bundle management
 * 
 * Now uses schema-derived types for consistency
 */

import type { CreateBundleInput } from '@api/types'
import type { Bundle } from '@api/types'

// Frontend form data for bundle creation/editing
// Derived from schema to ensure consistency
export type BundleFormData = Omit<CreateBundleInput, 'storeId'> & {
  storeId?: string // Optional for form editing
}

// Bundle management options
export interface BundleManagementOptions {
  storeId?: string
  isActive?: boolean
}

// Bundle display data with computed fields
// Extends schema-derived Bundle type with computed fields
export type BundleDisplayData = Bundle & {
  // Computed fields are already included in the schema-derived Bundle type
  // totalItems, individualPrice, bundlePrice, savings, savingsPercent
}

// Type transformers (using schema-derived types)
export function formDataToCreateInput(formData: BundleFormData, storeId: string): CreateBundleInput {
  return {
    storeId,
    name: formData.name,
    description: formData.description,
    imageUrl: formData.imageUrl,
    isActive: formData.isActive,
    sortIndex: formData.sortIndex,
    items: formData.items,
    pricing: formData.pricing
  }
}

export function formDataToUpdateInput(formData: Partial<BundleFormData>): Partial<CreateBundleInput> {
  return {
    name: formData.name,
    description: formData.description,
    imageUrl: formData.imageUrl,
    isActive: formData.isActive,
    sortIndex: formData.sortIndex,
    items: formData.items,
    pricing: formData.pricing
  }
}

export function bundleToFormData(bundle: Bundle): BundleFormData {
  return {
    name: bundle.name,
    description: bundle.description ?? '',
    imageUrl: bundle.imageUrl ?? '',
    isActive: bundle.isActive ?? true,
    sortIndex: bundle.sortIndex ?? 0,
    items: bundle.items?.map(item => ({
      itemId: item.itemId,
      quantity: item.quantity,
      sortIndex: item.sortIndex ?? 0
    })) ?? [],
    pricing: bundle.pricing ?? {
      pricingType: 'FIXED_PRICE' as const,
      showSavings: true
    }
  }
}

