/**
 * ResultsContainer — every branch exposes a clear next action (no dead ends).
 */
import { LoadingState } from './LoadingState'
import { ErrorState } from './ErrorState'
import { NoResults } from './NoResults'
import { SearchResults } from './SearchResults'
import { NoLocationPrompt } from './NoLocationPrompt'
import type { SearchStatus } from '@shared/hooks/hooks/useSearchOrchestration'
import type { LocationData } from '@shared/types'
import type { StoreWithDistance } from '@api/types'

export interface ResultsContainerProps {
  readonly searchStatus: SearchStatus
  readonly isLoading: boolean
  readonly location: LocationData | undefined
  readonly areaLabel: string | undefined
  readonly error: Error | undefined
  readonly stores: StoreWithDistance[] | undefined
  readonly userLocation: LocationData | undefined
  readonly onStoreClick: (store: StoreWithDistance) => void
  readonly onExpandToMiles: (miles: number) => void
  readonly searchRadiusMiles: number
  readonly onRetrySearch: () => void
  readonly onQuickCity: (city: string, state: string) => void
  readonly onPickNearbyCity: () => void
}

export function ResultsContainer({
  searchStatus,
  isLoading,
  location,
  areaLabel,
  error,
  stores,
  userLocation,
  onStoreClick,
  onExpandToMiles,
  searchRadiusMiles,
  onRetrySearch,
  onQuickCity,
  onPickNearbyCity,
}: ResultsContainerProps) {
  switch (searchStatus) {
    case 'no-location': {
      return <NoLocationPrompt onQuickCity={onQuickCity} />
    }
    case 'loading': {
      return (
        <LoadingState
          isLoading={isLoading}
          location={location}
          areaLabel={areaLabel}
        />
      )
    }
    case 'error': {
      return <ErrorState error={error} onRetry={onRetrySearch} />
    }
    case 'no-results': {
      return (
        <NoResults
          location={location}
          searchRadiusMiles={searchRadiusMiles}
          areaLabel={areaLabel}
          onExpandToMiles={onExpandToMiles}
          onPickNearbyCity={onPickNearbyCity}
        />
      )
    }
    case 'results': {
      return (
        <SearchResults
          error={error}
          location={location}
          stores={stores}
          userLocation={userLocation}
          onStoreClick={onStoreClick}
          areaLabel={areaLabel}
        />
      )
    }
    default: {
      return null
    }
  }
}

/**
 * ResultsSection - Component for the search results section wrapper;
 */
import React, { forwardRef } from 'react'
import { GeocodingError } from './GeocodingError'
import { DebugInfo } from './DebugInfo'
import type { SearchStatus } from '@shared/hooks/hooks/useSearchOrchestration'
import type { LocationData } from '@shared/types'
import type { StoreWithDistance } from '@api/types'

interface ResultsSectionProps {
  searchStatus: SearchStatus
  stores: StoreWithDistance[] | undefined;
  geocodingError: string | undefined;
  onClearGeocodingError: () => void;
  children: React.ReactNode;
  location: LocationData | undefined;
  error: Error | undefined;
  isProd: boolean;
}

const getStatusMessage = (status: SearchStatus, storeCount?: number) => {
  const storeText = storeCount === 1 ? 'store' : 'stores'

  switch (status) {
    case 'no-location': {
      return 'Enter a location to find stores.'
    }
    case 'loading': {
      return 'Searching for ' + storeText + '...'
    }
    case 'error': {
      return 'Store search failed. Retry or change your location.'
    }
    case 'no-results': {
      return 'No ' + storeText + ' found in this area.'
    }
    case 'results': {
      if (storeCount === 0) {
        return ' '
      }
      return `${storeCount ?? 0} ${storeText} found.`
    }
    default: {
      return ' '
    }
  }
}

export const ResultsSection = forwardRef<HTMLElement, ResultsSectionProps>(({
  searchStatus,
  stores,
  geocodingError,
  onClearGeocodingError,
  children,
  location,
  error,
  isProd
}, ref) => {
  const statusMessage = getStatusMessage(searchStatus, stores?.length)
  return (
    <section
      ref={ref}
      className="my-2 focus:outline-none focus:ring-2 focus:ring-purple-500 focus:ring-opacity-50 rounded-lg" 
      tabIndex={-1}
      role="region"
      aria-labelledby="results-heading"
      aria-busy={searchStatus === 'loading'}
    >
      {/* Hidden heading for ARIA reference */}
      <h2 id="results-heading" className="sr-only">Search results</h2>

      {/* Dedicated status live region for accessibility */}
      <div className="sr-only" role="status" aria-live="polite" aria-atomic="true">
        {statusMessage}
      </div>

      <GeocodingError
        geocodingError={geocodingError} 
        onClearGeocodingError={onClearGeocodingError} 
      />
      {children}
      {!isProd && <DebugInfo location={location} stores={stores} error={error} />}
    </section>
  )
})

/**
