      />

      <div className="mt-3 max-h-[120px] overflow-hidden rounded-lg shadow-md ring-1 ring-black/5 md:max-h-[160px]">
        <StoreMapLazy
          stores={stores || []}
          userLocation={
            userLocation
              ? { latitude: userLocation.latitude, longitude: userLocation.longitude }
              : undefined
