/**
 * OrderProgressTracker - Visual progress indicator for order status
 * Extracted from OrderTrackingPage for SRP compliance
 */
// Keep timeline labels customer-friendly. Backend may emit COMPLETED; treat it as DELIVERED.
const ORDER_STATUS_STEPS = ['PLACED', 'ACCEPTED', 'PREPARING', 'READY', 'DELIVERED'] as const

export interface OrderProgressTrackerProps {
  currentStatus: string
  /** Whether order is canceled */
  isCanceled?: boolean
}

export function OrderProgressTracker({ currentStatus, isCanceled = false }: OrderProgressTrackerProps) {
  const normalizedStatus = currentStatus === 'COMPLETED' ? 'DELIVERED' : currentStatus
  const currentStepIndex = ORDER_STATUS_STEPS.indexOf(normalizedStatus as any)

  if (isCanceled) {
    return (
      <div className="text-center py-8">
        <span className="text-6xl mb-3 block">❌</span>
        <p className="text-xl font-semibold text-gray-700">Order Canceled</p>
        <p className="text-sm text-gray-500 mt-2">This order has been canceled</p>
      </div>
    )
  }

  return (
    <div className="flex justify-between items-start py-6 relative">
      {ORDER_STATUS_STEPS.map((step, index) => {
        const isActive = index <= currentStepIndex
        const isCurrent = index === currentStepIndex

        return (
          <div key={step} className="flex flex-col items-center gap-2 flex-1 relative z-10">
            {/* Progress Dot */}
            <div 
              className={
                'w-12 h-12 rounded-full border-3 flex items-center justify-center text-base font-bold transition-all duration-300 ' +
                (isActive 
                  ? 'bg-blue-500 border-blue-500 text-white scale-110' 
                  : 'bg-gray-100 border-gray-300 text-gray-400'
                ) +
                (isCurrent ? ' ring-4 ring-blue-200 shadow-lg' : '')
              }
            >
              {isActive ? '✓' : index + 1}
            </div>

            {/* Step Label */}
            <div 
              className={
                'text-xs font-medium text-center transition-all duration-300 ' +
                (isActive ? 'text-gray-900' : 'text-gray-400') +
                (isCurrent ? ' font-bold' : '')
              }
            >
              {step === 'PLACED' && '🔔 Placed'}
              {step === 'ACCEPTED' && '✅ Accepted'}
              {step === 'PREPARING' && '👨‍🍳 Preparing'}
              {step === 'READY' && '🎉 Ready'}
              {step === 'DELIVERED' && '✅ Delivered'}
            </div>

            {/* Progress Line */}
            {index < ORDER_STATUS_STEPS.length - 1 && (
              <div 
                className={
                  'absolute top-6 left-[50%] w-full h-1 -z-10 transition-all duration-500 ' +
                  (isActive ? 'bg-blue-500' : 'bg-gray-200')
                }
              />
            )}
          </div>
        )
      })}
    </div>
  )
}

/**
 * OrderStatusBadge - Centralized order status rendering
 * Consolidates status display logic from VendorOrdersPage, OrderCard, OrderTrackingPage
 * Config-driven for easy maintenance and extension
 */
import { Badge } from '@shared/ui/primitives'
import type { UpdateOrderRequestStatusEnum } from '@api/types'

export type OrderStatus = UpdateOrderRequestStatusEnum

interface StatusConfig {
  icon: string
  label: string
  variant: 'default' | 'secondary' | 'destructive' | 'outline' | 'success' | 'warning'
}

const ORDER_STATUS_CONFIG: Partial<Record<OrderStatus, StatusConfig>> = {
  PENDING_PAYMENT: { icon: '💳', label: 'Pending Payment', variant: 'secondary' },
  PLACED: { icon: '🔔', label: 'New Order', variant: 'warning' },
  ACCEPTED: { icon: '✅', label: 'Accepted', variant: 'secondary' },
  PREPARING: { icon: '👨‍🍳', label: 'Preparing', variant: 'default' },
  READY: { icon: '🎉', label: 'Ready', variant: 'success' },
  OUT_FOR_DELIVERY: { icon: '🚗', label: 'Out for Delivery', variant: 'default' },
  DELIVERED: { icon: '✅', label: 'Done', variant: 'default' },
  COMPLETED: { icon: '✅', label: 'Completed', variant: 'success' },
  CANCELED: { icon: '❌', label: 'Canceled', variant: 'destructive' },
}

export interface OrderStatusBadgeProps {
  status: OrderStatus
  /** Show icon (default: true) */
  showIcon?: boolean
  /** Override label */
  customLabel?: string
}

export function OrderStatusBadge({ 
  status, 
  showIcon = true,
  customLabel 
}: OrderStatusBadgeProps) {
  const config = ORDER_STATUS_CONFIG[status]

  if (!config) {
    // Fallback for unknown statuses
    return <Badge variant="default">{status}</Badge>
  }

  const label = customLabel || config.label
  const displayText = showIcon ? `${config.icon} ${label}` : label

  return <Badge variant={config.variant}>{displayText}</Badge>
}

/**
 * Get status configuration for programmatic access
 */
export function getStatusConfig(status: OrderStatus): StatusConfig | undefined {
  return ORDER_STATUS_CONFIG[status]
}

/**
 * Check if order is in pending state (needs vendor attention)
 */
export function isOrderPending(status: OrderStatus): boolean {
  return ['PLACED', 'ACCEPTED', 'PREPARING'].includes(status)
}

/**
 * Check if order is in active state (customer waiting)
 */
export function isOrderActive(status: OrderStatus): boolean {
  return ['PENDING_PAYMENT', 'PLACED', 'ACCEPTED', 'PREPARING', 'READY', 'OUT_FOR_DELIVERY'].includes(status)
}

/**
 * Get status progression for tracking
 */
export const ORDER_STATUS_PROGRESSION: OrderStatus[] = [
  'PENDING_PAYMENT',
  'PLACED',
  'ACCEPTED',
  'PREPARING',
  'READY',
  'OUT_FOR_DELIVERY',
  'DELIVERED',
]

/**
 * Get next status in progression
 */
export function getNextStatus(currentStatus: OrderStatus): OrderStatus | undefined {
  const currentIndex = ORDER_STATUS_PROGRESSION.indexOf(currentStatus)
  if (currentIndex === -1 || currentIndex === ORDER_STATUS_PROGRESSION.length - 1) {
    return undefined
  }
  return ORDER_STATUS_PROGRESSION[currentIndex + 1] || undefined
}

/**
 * Order Actions Component
 * 
 * Extracted action buttons with status-specific logic.
 */

import { Button } from '@shared/ui/primitives'
import { isOrderActive, getActionButtonConfig } from '../../utils/orderUtils'

interface OrderActionsProps {
  status: string
  isDelivery: boolean
  onStatusUpdate: (orderId: string, newStatus: string) => void
  orderId: string
  className?: string
}

export function OrderActions({ 
  status, 
  isDelivery, 
  onStatusUpdate, 
  orderId, 
  className 
}: OrderActionsProps) {
  if (!isOrderActive(status)) return null

  const actionConfig = getActionButtonConfig(status, isDelivery)
  if (!actionConfig) return null

  const handleClick = (e: React.MouseEvent) => {
    e.stopPropagation()
    onStatusUpdate(orderId, actionConfig.nextStatus)
  }

  return (
    <div className={`flex gap-2 mt-4 pt-4 border-t border-gray-200 ${className}`}>
      <Button
        size="small"
        variant="primary"
        onClick={handleClick}
        className="flex-1"
        data-testid={`${status.toLowerCase().replace('_', '-')}-btn`}
        data-order-id={orderId}
      >
        {actionConfig.icon} {actionConfig.label}
      </Button>
    </div>
  )
}

