      )}

      {/* Header */}
      <div className="flex justify-between items-start mb-3">
        <div>
          <h3 className="text-lg font-bold text-gray-900 mb-1">
            {orderId}
          </h3>
          <OrderStatusBadge status={order.status} />
        </div>
        <div className="text-right">
          <span className={isUrgent ? 'text-red-600 font-bold text-sm' : 'text-gray-500 text-sm'}>
            {orderAge.display}
          </span>
        </div>
      </div>

      {/* Order Details */}
      <OrderDetails order={order} />

      {/* Quick Actions */}
      <OrderActions
        status={order.status}
        isDelivery={isDelivery}
        onStatusUpdate={onStatusUpdate}
        orderId={order.id}
      />
    </div>
  )
}

/**
 * Vendor Order Card Hook
 * 
 * Extracts state management and computed values for VendorOrderCard.
 */

import { useMemo } from 'react'
import { getOrderAge } from '@shared/lib/utils/orderHelpers'
import { isOrderUrgent } from '../../../utils/orderUtils'
import type { OrderResponse } from '@api/types'

export interface UseVendorOrderCardProps {
  order: OrderResponse
  isSelected: boolean
  isBulkMode?: boolean
  isBulkSelected?: boolean
}

export function useVendorOrderCard({
  order,
  isSelected,
  isBulkMode = false,
  isBulkSelected = false
}: UseVendorOrderCardProps) {
  // ========================================
  // Computed Values
  // ========================================

  const orderAge = useMemo(() => {
    return getOrderAge(order.createdAt || new Date().toISOString())
  }, [order.createdAt])

  const isUrgent = useMemo(() => {
    return isOrderUrgent(orderAge, order.status)
  }, [orderAge, order.status])

  const isDelivery = useMemo(() => {
    return order.deliveryType === 'DELIVERY'
  }, [order.deliveryType])

  const orderId = useMemo(() => {
    return `#${order.id.slice(0, 8).toUpperCase()}`
  }, [order.id])

  // ========================================
  // Card Styling
  // ========================================

  const cardClasses = useMemo(() => {
    const baseClasses = 'bg-white rounded-lg p-4 border-2 cursor-pointer transition-all duration-200'

    const selectionClasses = isBulkMode && isBulkSelected 
      ? 'border-blue-500 shadow-lg ring-2 ring-blue-200'
      : (isSelected 
        ? 'border-blue-500 shadow-lg ring-2 ring-blue-200'
        : 'border-gray-200 hover:border-gray-300 hover:shadow-md')

    const urgencyClasses = isUrgent ? ' border-l-4 border-l-red-500 bg-red-50' : ''

    return `${baseClasses} ${selectionClasses} ${urgencyClasses}`
  }, [isSelected, isBulkMode, isBulkSelected, isUrgent])

  return {
    orderAge,
    isUrgent,
    isDelivery,
    orderId,
    cardClasses
  }
}

/**
 * Order Status Mapping Utilities
 * 
 * Provides centralized order status management and validation logic.
 */

export type OrderStatus = 'PLACED' | 'ACCEPTED' | 'PREPARING' | 'READY' | 'OUT_FOR_DELIVERY' | 'COMPLETED' | 'CANCELLED'

export interface OrderStatusConfig {
  variant: 'warning' | 'secondary' | 'default' | 'success' | 'destructive'
  label: string
  canTransitionTo: OrderStatus[]
  actionLabel?: string
  actionIcon?: string
}

// ========================================
// Order Status Configuration
// ========================================

export const ORDER_STATUS_CONFIG: Record<OrderStatus, OrderStatusConfig> = {
  PLACED: {
    variant: 'warning',
    label: 'Placed',
    canTransitionTo: ['ACCEPTED', 'CANCELLED'],
    actionLabel: 'Accept',
    actionIcon: '✅'
  },
  ACCEPTED: {
    variant: 'secondary',
    label: 'Accepted',
    canTransitionTo: ['PREPARING', 'CANCELLED'],
    actionLabel: 'Start Preparing',
    actionIcon: '👨‍🍳'
  },
  PREPARING: {
    variant: 'default',
    label: 'Preparing',
    canTransitionTo: ['READY'],
    actionLabel: 'Mark Ready',
    actionIcon: '🎉'
  },
  READY: {
    variant: 'success',
    label: 'Ready',
    canTransitionTo: ['OUT_FOR_DELIVERY', 'COMPLETED'],
    actionLabel: 'Out for Delivery',
    actionIcon: '🚗'
  },
  OUT_FOR_DELIVERY: {
    variant: 'success',
    label: 'Out for Delivery',
    canTransitionTo: ['COMPLETED'],
    actionLabel: 'Delivered',
    actionIcon: '✅'
  },
  COMPLETED: {
    variant: 'default',
    label: 'Completed',
    canTransitionTo: [],
    actionLabel: undefined,
    actionIcon: undefined
  },
  CANCELLED: {
    variant: 'destructive',
    label: 'Cancelled',
    canTransitionTo: [],
    actionLabel: undefined,
    actionIcon: undefined
  }
}

// ========================================
// Status Mapping Functions
// ========================================

/**
 * Get status configuration for an order
 */
export function getOrderStatusConfig(status: string): OrderStatusConfig {
  return ORDER_STATUS_CONFIG[status as OrderStatus] || ORDER_STATUS_CONFIG.PLACED
}

/**
 * Get badge variant for order status
 */
export function getStatusBadgeVariant(status: string): OrderStatusConfig['variant'] {
  return getOrderStatusConfig(status).variant
}

/**
 * Get action button configuration for current status
 */
export function getActionButtonConfig(status: string, isDelivery: boolean) {
  const config = getOrderStatusConfig(status)

  if (!config.actionLabel) return null

  let actionLabel = config.actionLabel
  let nextStatus = config.canTransitionTo[0] // Take first available transition

  // Special handling for READY status based on delivery type
  if (status === 'READY') {
    actionLabel = isDelivery ? '🚗 Out' : '✅ Delivered'
    nextStatus = isDelivery ? 'OUT_FOR_DELIVERY' : 'COMPLETED'
  }

  return {
    label: actionLabel,
    nextStatus,
    icon: config.actionIcon
  }
}

/**
 * Check if order is in active state (has available actions)
 */
export function isOrderActive(status: string): boolean {
  const config = getOrderStatusConfig(status)
  return config.canTransitionTo.length > 0
}

/**
 * Check if order is urgent (older than 15 minutes and in early stages)
 */
export function isOrderUrgent(orderAge: { minutes: number }, status: string): boolean {
  return orderAge.minutes > 15 && ['PLACED', 'ACCEPTED'].includes(status)
}

/**
 * Parse order items safely
 */
export function parseOrderItems(items: any): any[] {
  try {
    return typeof items === 'string' ? JSON.parse(items) : items || []
  } catch {
    return []
  }
}

/**
 * Get display items (first 2 items) and count of remaining items
 */
export function getOrderItemsDisplay(items: any[]) {
  const displayItems = items.slice(0, 2)
  const remainingCount = Math.max(0, items.length - 2)

  return {
    displayItems,
    remainingCount,
    hasMore: remainingCount > 0
  }
}

/**
 * ItemCard - Display menu item with SEO-friendly URLs;
 */
import { Link } from 'react-router-dom'
import { Card, Badge, Button, Image } from '@shared/ui/primitives'
import { useAddToCart } from '@shared/hooks/hooks/useAddToCart'
import { getItemRouteSimple } from '@shared/lib/utils/navigation/routes'
import type { ItemResponse } from '@api/types'
import { formatCurrency } from '@shared/lib/utils/format'
import { parsePrice } from '@shared/lib/utils/format'
//  // File not found

export interface ItemCardProps {
  item: ItemResponse;
  /** Optional store context for better SEO URLs */
  store?: { id: string; name: string }
}

export function ItemCard({ item, store }: ItemCardProps) {
  const price = parsePrice(item.price)
  const addToCart = useAddToCart()
  
  const imageUrl = (item as any).imageUrl;
  // Generate SEO-friendly item route;
  const itemRoute = getItemRouteSimple({ id: item.id, title: item.title })

  const handleAddToCart = (e: React.MouseEvent) => {
    e.preventDefault()
    e.stopPropagation()
    
    addToCart.mutate({
      storeId: item.storeId,
      itemId: item.id,
      quantity: 1,
      title: item.title,
      unitPrice: item.price,
      item})
  }

  return (
    <Card className="item-card">
      <Image
        src={imageUrl || '/placeholder-item-' + item.id + '.jpg'}
        alt={item.title}
        fallbackSeed={item.id}
        aspectRatio="4/3"
        containerClassName="item-card__image"
      />
      <div className="item-card__content">
        <div className="item-card__header">
          <Link to={itemRoute} className="item-card__title-link">
            <h4 className="item-card__title">{item.title}</h4>
          </Link>
          <span className="item-card__price">{formatCurrency(price)}</span>
        </div>

        {item.description && (
          <p className="item-card__description">{item.description}</p>
        )}

        <div className="item-card__footer">
          <div className="item-card__badges">
            {item.isSoldOut && <Badge variant="destructive">Sold Out</Badge>}
            {!item.isActive && <Badge variant="warning">Inactive</Badge>}
          </div>
          
          <Button
            variant="primary"
            size="small"
            onClick={handleAddToCart}
            disabled={item.isSoldOut || !item.isActive || addToCart.isPending}
            className="item-card__add-button"
          >
            {addToCart.isPending ? 'Adding...' : 'Add to Cart'}
          </Button>
        </div>
      </div>
    </Card>
  )
}

/**
 * ItemCarouselCompact - Full-screen sliding product carousel
 */
import type { TouchEvent } from 'react';
import { useState, useRef, useCallback, useMemo } from 'react'
import { Image, SWIPE_THRESHOLD_PX, NAV_SYMBOL, ARIA_LABEL } from '@shared/ui/primitives'
import type { ItemResponse } from '@api/types'
import { formatCurrency } from '@shared/lib/utils/format'
import { parsePrice } from '@shared/lib/utils/format'
import { getImageUrl } from '@shared/lib/utils/image'
//  // File not found

export interface ItemCarouselCompactProps {
  items: ItemResponse[]
  storeName: string
  onClose?: () => void
}

export function ItemCarouselCompact({ items, storeName, onClose }: ItemCarouselCompactProps) {
  const [currentIndex, setCurrentIndex] = useState(0)
  const touchStartX = useRef<number>(0)

  const itemsLength = items.length
  const hasItems = itemsLength > 0
  const hasMultipleItems = itemsLength > 1
  const isFirstSlide = currentIndex === 0
  const isLastSlide = currentIndex === itemsLength - 1

  const goToSlide = useCallback((index: number) => {
    setCurrentIndex(Math.max(0, Math.min(index, itemsLength - 1)))
  }, [itemsLength])

  const goNext = useCallback(() => {
    if (!isLastSlide) {
      setCurrentIndex(prev => prev + 1)
    }
  }, [isLastSlide])

  const goPrevious = useCallback(() => {
    if (!isFirstSlide) {
      setCurrentIndex(prev => prev - 1)
    }
  }, [isFirstSlide])

  const handleTouchStart = useCallback((e: TouchEvent) => {
    if (e.touches[0]) {
      touchStartX.current = e.touches[0].clientX
    }
  }, [])

  const handleTouchEnd = useCallback((e: TouchEvent) => {
    if (!e.changedTouches[0]) return
    const touchEndX = e.changedTouches[0].clientX
    const diff = touchStartX.current - touchEndX
    
    if (Math.abs(diff) > SWIPE_THRESHOLD_PX) {
      if (diff > 0) {
        goNext()
      } else {
        goPrevious()
      }
    }
  }, [goNext, goPrevious])

  const currentItem = useMemo(() => items[currentIndex], [items, currentIndex])
  const price = useMemo(() => parsePrice(currentItem?.price || '0'), [currentItem])
  const imageUrl = useMemo(() => getImageUrl((currentItem as any)?.imageUrl, currentItem?.id || '', 'item'), [currentItem])

  if (!hasItems) return

  return (
    <div className="item-carousel">
      <div 
        className="item-carousel__slide"
        onTouchStart={handleTouchStart}
        onTouchEnd={handleTouchEnd}
      >
        <Image
          src={imageUrl}
          alt={currentItem?.title || 'Item'}
          fallbackSeed={currentItem?.id || 'unknown'}
          className="item-carousel__image"
        />
        
        <div className="item-carousel__overlay" />
        
        <div className="item-carousel__content">
          <h1 className="item-carousel__title">{currentItem?.title || 'Item'}</h1>
          <div className="item-carousel__meta">
            <p className="item-carousel__store">{storeName}</p>
            <p className="item-carousel__price">{formatCurrency(price)}</p>
          </div>
        </div>
      </div>

      {/* Navigation Controls */}
      {!isFirstSlide && (
        <button
          type="button"
          className="item-carousel__nav item-carousel__nav--prev"
          onClick={goPrevious}
          aria-label={ARIA_LABEL.PREVIOUS_ITEM}
        >
          {NAV_SYMBOL.LEFT}
        </button>
      )}
      
      {!isLastSlide && (
        <button
          type="button"
          className="item-carousel__nav item-carousel__nav--next"
          onClick={goNext}
          aria-label={ARIA_LABEL.NEXT_ITEM}
        >
          {NAV_SYMBOL.RIGHT}
        </button>
      )}

      {/* Dots Indicator */}
      {hasMultipleItems && (
        <div className="item-carousel__dots">
          {items.map((_, index) => (
            <button
              key={index}
              type="button"
              className={`item-carousel__dot ${index === currentIndex ? 'item-carousel__dot--active' : ''}`}
              onClick={() => goToSlide(index)}
              aria-label={ARIA_LABEL.GO_TO_ITEM(index)}
            />
          ))}
        </div>
      )}

      {/* Close Button */}
      {onClose && (
        <button
          type="button"
          className="item-carousel__close"
          onClick={onClose}
          aria-label={ARIA_LABEL.CLOSE_CAROUSEL}
        >
          {NAV_SYMBOL.CLOSE}
        </button>
      )}
    </div>
  )
}

/**
 * ProductCard - Display product information for carousels and grids
 * Designed for search results and featured product sections
 */
import { memo, useCallback, useMemo } from 'react'
import { Card, Image, ICON, ASPECT_RATIO, LABEL } from '@shared/ui/primitives'
import { getImageUrl } from '@shared/lib/utils/image'
import type { ProductClickHandler, ItemResponse } from '@api/types'

export interface ProductCardProps {
  product: ItemResponse
  onClick?: ProductClickHandler | undefined
  variant?: 'standard' | 'compact' | undefined
  showStore?: boolean | undefined
}

const PRICE_DECIMALS = 2

function ProductCardComponent({ 
  product, 
  onClick,
  variant = 'standard',
  showStore = true
}: ProductCardProps) {
  const handleClick = useCallback(() => onClick?.(product), [onClick, product])
  
  const isCompact = variant === 'compact'
  const imageUrl = useMemo(
    () => getImageUrl(undefined, product.id, 'product'),
    [product.id]
  )
  const aspectRatio = isCompact ? ASPECT_RATIO.SQUARE : ASPECT_RATIO.LANDSCAPE
  const formattedPrice = useMemo(
    () => '$' + Number.parseFloat(product.price).toFixed(PRICE_DECIMALS) + '',
    [product.price]
  )

  return (
    <Card 
      onClick={handleClick} 
      className={`bg-card rounded-xl border shadow-sm p-4 ${isCompact ? 'max-w-[260px]' : ''}`}
    >
      <div className="">
        <Image
          src={imageUrl}
          alt={product.title}
          fallbackSeed={product.id}
          aspectRatio={aspectRatio}
          containerClassName="w-full rounded-md overflow-hidden"
        />
        {!product.isActive && (
          <div className="">
            {LABEL.SOLD_OUT}
          </div>
        )}
      </div>
      
      <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="max-w-7xl mx-auto mb-6 flex justify-between items-start gap-4">
          <h4 className="">{product.title}</h4>
          <span className="font-bold text-primary">
            {formattedPrice}
          </span>
        </div>
        
        {!isCompact && product.description && (
          <p className="">{product.description}</p>
        )}
        
        {showStore && (
          <div className="text-xl font-semibold mb-1">
            <span className="">{ICON.STORE}</span>
            Store ID: {product.storeId}
          </div>
        )}
      </div>
    </Card>
  )
}

export const ProductCard = memo(ProductCardComponent)

