import { useState } from 'react'
import type { MediaItem } from '@api/types'
import { getYouTubeEmbedUrl } from '@shared/hooks/hooks/useMediaDetection'
import { Image } from '@shared/ui/primitives'

interface PostMediaProps {
  readonly media: MediaItem[]
  readonly postId: string
}

function YouTubeEmbed({ url }: { url: string }) {
  const embedUrl = getYouTubeEmbedUrl(url)
  if (!embedUrl) return null
  return (
    <iframe
      src={embedUrl}
      title="YouTube video"
      style={{ border: 'none' }}
      allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
      allowFullScreen
      className="absolute inset-0 w-full h-full"
    />
  )
}

function MediaCell({
  item,
  index,
  postId,
  className = '',
}: {
  item: MediaItem
  index: number
  postId: string
  className?: string
}) {
  if (item.type === 'youtube') {
    return (
      <div className={`relative overflow-hidden rounded-lg bg-black ${className}`}>
        <YouTubeEmbed url={item.url ?? ''} />
      </div>
    )
  }
  return (
    <div className={`relative overflow-hidden rounded-lg bg-muted ${className}`}>
      <Image
        src={item.url ?? ''}
        alt={`Post ${postId} media ${index + 1}`}
        className="absolute inset-0 w-full h-full object-cover"
      />
    </div>
  )
}

export const PostMedia = ({ media, postId }: PostMediaProps) => {
  const [selectedIndex, setSelectedIndex] = useState(0)

  if (media.length === 0) return null

  const safeIndex = Math.min(selectedIndex, media.length - 1)

  const handleThumbnailClick = (index: number, e: React.MouseEvent) => {
    e.stopPropagation()
    setSelectedIndex(index)
  }

  // Single item
  if (media.length === 1) {
    const item = media[0]
    return (
      <div className="mb-3">
        <MediaCell
          item={item}
          index={0}
          postId={postId}
          className={item.type === 'youtube' ? 'aspect-video' : 'aspect-[4/3]'}
        />
      </div>
    )
  }

  // Two items side by side
  if (media.length === 2) {
    return (
      <div className="mb-3 grid grid-cols-2 gap-1">
        {media.map((item, index) => (
          <MediaCell
            key={item.url ?? `${item.type}-${index}`}
            item={item}
            index={index}
            postId={postId}
            className="aspect-square"
          />
        ))}
      </div>
    )
  }

  // 3+ items: main viewer + thumbnail strip
  return (
    <div className="mb-3 space-y-1.5">
      <MediaCell
        item={media[safeIndex]}
        index={safeIndex}
        postId={postId}
        className="aspect-video"
      />
      <div className="flex gap-1.5 overflow-x-auto pb-0.5">
        {media.map((item, index) => (
          <button
            key={item.url ?? `${item.type}-${index}`}
            type="button"
            onClick={(e) => handleThumbnailClick(index, e)}
            className={[
              'flex-shrink-0 w-16 h-16 rounded-md overflow-hidden transition-all duration-150 bg-muted',
              index === safeIndex
                ? 'ring-2 ring-primary ring-offset-1'
                : 'opacity-60 hover:opacity-100',
            ].join(' ')}
          >
            {item.thumbnail ? (
              <img
                src={item.thumbnail}
                alt={`Thumbnail ${index + 1}`}
                className="w-full h-full object-cover"
              />
            ) : (
              <div className="w-full h-full flex items-center justify-center">
                <svg className="w-4 h-4 text-muted-foreground" viewBox="0 0 24 24" fill="currentColor">
                  <path d="M8 5v14l11-7z" />
                </svg>
              </div>
            )}
          </button>
        ))}
      </div>
    </div>
  )
}

/**
 * useUnifiedSearch - Central hook for all search functionality
 * Supports stores, products, and future entity types
 */
import { useState, useCallback, useMemo } from 'react'
import { useQuery } from '@tanstack/react-query'
import { groupResultsByType } from '../types/search.types'
import type { 
  SearchFilters, 
  SearchResponse,
  SearchEntityType 
} from '../types/search.types'

export interface UseUnifiedSearchOptions {
  initialFilters?: SearchFilters
  enabled?: boolean
  debounceMs?: number
}

export function useUnifiedSearch(options: UseUnifiedSearchOptions = {}) {
  const {
    initialFilters = {},
    enabled = true
    // debounceMs - TODO: Implement debouncing when needed
  } = options

  const [filters, setFilters] = useState<SearchFilters>(initialFilters)

  // Main search query
  const searchQuery = useQuery<SearchResponse, Error>({
    queryKey: ['unified-search', filters],
    queryFn: async () => {
      // TODO: Replace with actual API call
      // For now, mock the response structure
      return mockSearchApi(filters)
    },
    enabled: enabled && (!!filters.query || !!filters.location),
    staleTime: 30_000, // 30 seconds
  })

  // Update filters
  const updateFilters = useCallback((updates: Partial<SearchFilters>) => {
    setFilters(prev => ({ ...prev, ...updates }))
  }, [])

  // Update query
  const setQuery = useCallback((query: string) => {
    updateFilters({ query })
  }, [updateFilters])

  // Update location
  const setLocation = useCallback((location: SearchFilters["location"]) => {
    if (location) {
      updateFilters({ location })
    }
  }, [updateFilters])

  // Update entity types filter
  const setEntityTypes = useCallback((types: SearchEntityType[]) => {
    updateFilters({ entityTypes: types })
  }, [updateFilters])

  // Update sort
  const setSortBy = useCallback((sortBy: SearchFilters["sortBy"]) => {
    if (sortBy) {
      updateFilters({ sortBy })
    }
  }, [updateFilters])

  // Clear all filters
  const clearFilters = useCallback(() => {
    setFilters(initialFilters)
  }, [initialFilters])

  // Reset search
  const resetSearch = useCallback(() => {
    setFilters({})
  }, [])

  // Group results by type using centralized helper
  const groupedResults = useMemo(() => 
    searchQuery.data?.items 
      ? groupResultsByType(searchQuery.data.items)
      : { stores: [], products: [] },
    [searchQuery.data]
  )

  return {
    // State
    filters,
    results: searchQuery.data,
    groupedResults,

    // Loading states
    isLoading: searchQuery.isLoading,
    isError: searchQuery.isError,
    error: searchQuery.error,

    // Actions
    updateFilters,
    setQuery,
    setLocation,
    setEntityTypes,
    setSortBy,
    clearFilters,
    resetSearch,

    // React Query utilities
    refetch: searchQuery.refetch,
    isRefetching: searchQuery.isRefetching,
  }
}

/**
 * Mock API for development
 * Replace with actual API integration
 */
async function mockSearchApi(filters: SearchFilters): Promise<SearchResponse> {
  // Simulate network delay
  await new Promise(resolve => setTimeout(resolve, 500))

  // Mock response
  return {
    items: [],
    total: 0,
    page: 1,
    pageSize: 20,
    hasMore: false,
    query: filters.query || '',
    filters,
    facets: {
      entityCounts: {
        store: 0,
        product: 0,
        post: 0,
        category: 0
      }
    }
  }
}

/**
 * Search Result Transformers
 * Convert search results to component-specific types
 */
import type { StoreSearchResult, ProductSearchResult } from '../types/search.types'
import type { StoreWithDistance, ItemResponse } from '@api/types'

/**
 * Transform search result to StoreWithDistance
 */
export function transformStoreResult(result: StoreSearchResult): StoreWithDistance {
  return {
    id: result.id,
    name: result.name,
    description: result.description,
    distance: result.distance,
    prepTimeMin: result.prepTimeMin,
    isPublished: result.isOpen ?? true,
    // Add other required Store fields with defaults
  } as StoreWithDistance
}

/**
 * Transform search result to Product
 */
export function transformProductResult(result: ProductSearchResult): ItemResponse {
  // Create a minimal ItemResponse with all required properties
  return {
    id: result.id,
    storeId: result.storeId || '',
    store: undefined, // Will be populated if needed
    title: result.title || 'Unknown Product',
    description: result.description || '',
    price: typeof result.price === 'number' ? result.price.toString() : (result.price || '0'),
    isActive: result.isActive || false,
    isSoldOut: result.isSoldOut || false,
    sortIndex: result.sortIndex || 0,
    stockQty: 0, // Default value since stockQty doesn't exist on ProductSearchResult
    optionsJson: null,
    allergensJson: null,
    nutritionJson: null,
    category: result.category || '',
    imageUrl: result.imageUrl || '',
    isVegan: false,
    isVegetarian: false,
    isGlutenFree: false,
    isDairyFree: false,
    isNutFree: false,
    isSpicy: false,
    isOrganic: false,
    isKeto: false,
    isLowCarb: false,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  } as unknown as ItemResponse
}

/**
 * Batch transform stores
 */
export function transformStoreResults(results: StoreSearchResult[]): StoreWithDistance[] {
  return results.map(transformStoreResult)
}

/**
 * Batch transform products
 */
export function transformProductResults(results: ProductSearchResult[]): ItemResponse[] {
  return results.map(transformProductResult)
}

/**
 * CityStateInput - Search by city name with optional state;
 * Uses smart fallbacks and database caching to save API quota;
 */
import { useState } from 'react'
import styles from './LocationSearch.module.css'

interface CityStateInputProps {
  readonly onCitySubmit: (city: string, state?: string) => void;
  readonly isLoading?: boolean;
}

export function CityStateInput({ onCitySubmit, isLoading }: CityStateInputProps) {
  const [cityInput, setCityInput] = useState('')
  const [stateInput, setStateInput] = useState('')

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    
    const city = cityInput.trim()
    const state = stateInput.trim()
    
    if (!city) return;
    onCitySubmit(city, state || undefined)
  }

  return (
    <form onSubmit={handleSubmit} className="">
      <div className="">
        <input
          type="text"
          className=""
          value={cityInput}
          onChange={(e) => setCityInput(e.target.value)}
          placeholder="City name (e.g., Austin)"
          disabled={isLoading}
        />
        <input
          type="text"
          className=""
          value={stateInput}
          onChange={(e) => setStateInput(e.target.value.toUpperCase())}
          placeholder="ST"
          maxLength={2}
          disabled={isLoading}
        />
      </div>
      <button
        type="submit" 
        className=""
        disabled={!cityInput.trim() || isLoading}
      >
        {isLoading ? 'Searching...' : 'Search by City'}
      </button>
    </form>
  )
}

/**
 * LocationSearch - Consolidated location input component
 * Uses the unified LocationService with localStorage persistence
 * Always shows search controls to allow new location searches
 */
import { useState, useEffect, useRef, useCallback, useMemo } from 'react'
import { useLocation } from '@shared/hooks/hooks/useLocation'
import type { LocationData } from '@shared/types/types/location.types'
import { CurrentLocationBadge } from './CurrentLocationBadge'
import { GeolocationButton } from './GeolocationButton'
import { ZipCodeInput } from './ZipCodeInput'
import { CityStateInput } from './CityStateInput'
import { RadiusControl } from './RadiusControl'
import { LocationHistory } from './LocationHistory'
import styles from './LocationSearch.module.css'

interface LocationSearchProps {
  readonly onLocationChange: (location: LocationData | undefined) => void
  readonly initialRadius?: number
  readonly showHistory?: boolean
}

export function LocationSearch({ 
  onLocationChange, 
  initialRadius = 25,
  showHistory = true 
}: LocationSearchProps) {
  const {
    currentLocation,
    isLoading,
    error,
    getLocation,
    clearLocation,
    updateRadius,
    locationHistory,
    preferences,
    updatePreferences,
    isGeolocationSupported
  } = useLocation()

  // OPTIMIZED: Simplified state - no object wrapper needed
  const [activeInput, setActiveInput] = useState<'geolocation' | 'zip' | 'city' | undefined>()

  // Use ref to store the latest callback to avoid infinite loops
  const onLocationChangeRef = useRef(onLocationChange)
  onLocationChangeRef.current = onLocationChange

  // OPTIMIZED: One-time radius seeding to prevent flicker
  const [radiusInitialized, setRadiusInitialized] = useState(false)
  useEffect(() => {
    if (!radiusInitialized && initialRadius !== preferences.preferredRadius) {
      updateRadius(initialRadius)
      setRadiusInitialized(true)
    }
  }, [initialRadius, preferences.preferredRadius, updateRadius, radiusInitialized])

  // Notify parent of location changes - only when location actually changes
  useEffect(() => {
    onLocationChangeRef.current(currentLocation)
  }, [currentLocation])

  // OPTIMIZED: Memoized location handler with proper error handling
  const handleLocationRequest = useCallback(async (
    type: 'geolocation' | 'zip' | 'city',
    value: string,
    state?: string
  ) => {
    setActiveInput(type)
    try {
      if (type === 'city' && !state) {
        throw new Error('Please provide a state abbreviation (e.g., TX, CA, NY)')
      }
      await getLocation({ type, value, ...(state && { state }) })
    } catch (error: unknown) {
      // Log error for debugging while hook handles user feedback
      console.warn('Location request failed:', error)
    } finally {
      setActiveInput(undefined)
    }
  }, [getLocation])

  // OPTIMIZED: Memoized handlers to prevent unnecessary re-renders
  const handleUseMyLocation = useCallback(() => handleLocationRequest('geolocation', ''), [handleLocationRequest])
  const handleZipSubmit = useCallback((zipCode: string) => handleLocationRequest('zip', zipCode), [handleLocationRequest])
  const handleCitySubmit = useCallback((city: string, state?: string) => handleLocationRequest('city', city, state), [handleLocationRequest])

  // Handle radius change
  const handleRadiusChange = useCallback((newRadius: number) => {
    updateRadius(newRadius)
  }, [updateRadius])

  // Handle clear location
  const handleClear = useCallback(() => {
    clearLocation()
  }, [clearLocation])

  // OPTIMIZED: Type-safe history selection with information preservation
  const handleHistorySelect = useCallback(async (location: LocationData) => {
    try {
      // Type-safe mapping with validation
      const getLocationType = (source: string): 'geolocation' | 'zip' | 'city' => {
        switch (source) {
          case 'geolocation': {
            return 'geolocation'
          }
          case 'zip': {
            return 'zip'
          }
          case 'city':
          case 'address':
          case 'manual':
          case 'search':
          default: {
            return 'city'
          }
        }
      }

      const inputType = getLocationType(location.source)

      // Preserve original search data to avoid information loss
      const searchValue = location.zip ?? location.city ?? location.displayName ?? ''
      const searchState = location.state ?? undefined

      // Validate required data for city searches
      if (inputType === 'city' && !searchValue) {
        throw new Error('Cannot replay location: missing city information')
      }

      await getLocation({
        type: inputType,
        value: searchValue,
        ...(searchState && { state: searchState })
      })
    } catch (error: unknown) {
      console.warn('History selection failed:', error)
    }
  }, [getLocation])

  // Handle set as default
  const handleSetAsDefault = useCallback((location: LocationData) => {
    updatePreferences({ defaultLocation: location })
  }, [updatePreferences])

  // OPTIMIZED: Memoized loading state coordination
  const loadingStates = useMemo(() => ({
    geolocation: activeInput === 'geolocation' && isLoading,
    zip: activeInput === 'zip' && isLoading,
    city: activeInput === 'city' && isLoading,
    any: isLoading // For general loading state
  }), [activeInput, isLoading])

  return (
    <div
      className="w-full space-y-4"
      aria-busy={loadingStates.any}
      aria-live="polite"
    >
      {/* Current Location Display */}
      {currentLocation && (
        <CurrentLocationBadge
          locationName={currentLocation.displayName ?? 'Unknown Location'}
          radiusMiles={currentLocation.radiusMiles}
          onClear={handleClear}
          onSetDefault={() => handleSetAsDefault(currentLocation)}
        />
      )}

      {/* OPTIMIZED: Consolidated search controls with coordinated loading states */}
      <div className="">
        {isGeolocationSupported && (
          <>
            <GeolocationButton
              onGetLocation={() => { void handleUseMyLocation() }}
              isLoading={loadingStates.geolocation}
            />
            <div className="">
              <span>or</span>
            </div>
          </>
        )}

        <ZipCodeInput 
          onZipSubmit={(zipCode) => { void handleZipSubmit(zipCode) }}
          isLoading={loadingStates.zip}
        />

        <div className="">
          <span>or</span>
        </div>

        <CityStateInput 
          onCitySubmit={(city, state) => { void handleCitySubmit(city, state) }}
          isLoading={loadingStates.city}
        />
      </div>

      {/* Location History - Always show when available for quick switching */}
      {showHistory && locationHistory.length > 0 && (
        <LocationHistory
          history={locationHistory}
          onSelect={(location) => { void handleHistorySelect(location) }}
          onSetDefault={handleSetAsDefault}
        />
      )}

      {/* Radius Control (always visible) */}
      <RadiusControl
        radius={preferences.preferredRadius}
        onRadiusChange={handleRadiusChange}
      />

      {/* Error Message with Recovery Action */}
      {error && (
        <div className="flex flex-col items-center justify-center min-h-[400px] gap-4 text-destructive" role="alert" aria-live="polite">
          <span className="" aria-hidden="true">⚠️</span>
          <span>{error}</span>
          <button 
            className=""
            onClick={() => window.location.reload()}
            aria-label="Try again"
          >
            Try Again
          </button>
        </div>
      )}
    </div>
  )
}

/**
 * Single fallback discovery strip — global picks when API returns arbitrary stores.
 * Shown only when the page needs filler (see Home visibility rules).
 */
import { StoreCarousel } from '../StoreCarousel'
import { useFeaturedStores } from '@shared/hooks/hooks/store'

export interface PopularStoresRowProps {
  readonly enabled: boolean
  readonly title?: string
}

export function PopularStoresRow({ enabled, title = 'Popular stores' }: PopularStoresRowProps) {
  const { data: stores, isLoading } = useFeaturedStores(6, { enabled })
  if (!enabled) {
    return null
  }
  return (
    <div className="mt-3 opacity-95">
      <StoreCarousel
        stores={(stores ?? []).slice(0, 6)}
        title={title}
        isLoading={isLoading}
        variant="fallback"
      />
    </div>
  )
}

