            <span className="">{store.prepTimeMin} min</span>
          </div>

          {typedStore.deliveryFee ? (
            <div className="">
              <span className="">💰</span>
              <span className="">
                ${typedStore.deliveryFee.toFixed(2)} delivery
              </span>
            </div>
          ) : undefined}
        </div>

        {/* Primary action */}
        <Button 
          fullWidth 
          size="large" 
          onClick={handleViewMenu}
          className=""
        >
          View Menu →
        </Button>
      </div>
    </div>
  )
}

/**
