        const result = consistentSchemas.email.safeParse(email)
        expect(result.success).toBe(false)
      }
    })

    it('should have compatible password validation', () => {
      const validPasswords = [
        'password123',
        'SecurePass123!',
        'VeryLongPassword123'
      ]

      const invalidPasswords = [
        '123',
        'short',
        'password',
        ''
      ]

      for (const password of validPasswords) {
        const result = consistentSchemas.password.safeParse(password)
        expect(result.success).toBe(true)
      }

      for (const password of invalidPasswords) {
        const result = consistentSchemas.password.safeParse(password)
        expect(result.success).toBe(false)
      }
    })
  })

  describe('Schema Statistics', () => {
    it('should have reasonable schema counts', () => {
      const stats = getSchemaUsageStats()

      expect(stats.totalSchemas).toBeGreaterThan(0)
      expect(stats.unifiedSchemas).toBeGreaterThan(20) // Should have many unified schemas
      expect(stats.consistentSchemas).toBeGreaterThan(5) // Should have several consistent schemas
    })
  })

  describe('Consistency Report', () => {
    it('should generate a valid consistency report', () => {
      const report = generateConsistencyReport()

      expect(report).toContain('# Schema Consistency Report')
      expect(report).toContain('## Status:')
      expect(report).toContain('## Statistics')
      expect(report).toContain('## Recommendations')
    })

    it('should indicate valid status in report', () => {
      const report = generateConsistencyReport()
      const validation = validateSchemaConsistency()

      if (validation.isValid) {
        expect(report).toContain('✅ VALID')
      } else {
        expect(report).toContain('❌ INVALID')
      }
    })
  })

  describe('Schema Type Safety', () => {
    it('should have proper TypeScript types', () => {
      // Test that types are properly inferred
      type LoginData = typeof consistentSchemas.loginForm._input
      type SignupData = typeof consistentSchemas.signupForm._input

      const loginData: LoginData = {
        email: 'test@example.com',
        password: 'password123'
      }

      const signupData: SignupData = {
        email: 'test@example.com',
        password: 'password123',
        name: 'Test User'
      }

      expect(loginData).toBeDefined()
      expect(signupData).toBeDefined()
    })
  })
})

#!/usr/bin/env tsx
// @ts-nocheck

/**
 * Redundancy Cleanup Script
 * 
 * This script automates the removal of redundant and legacy code:
 * 1. Identifies deprecated files and code
 * 2. Removes duplicate type definitions
 * 3. Updates imports to use centralized types
 * 4. Replaces console logs with proper logging
 * 5. Removes unused code
 */

import { readFileSync, writeFileSync, existsSync, unlinkSync, readdirSync } from 'node:fs'
import { join, dirname } from 'node:path'
import { execSync } from 'node:child_process'

// ============================================
// Configuration
// ============================================

const CONFIG = {
  srcPath: './src',
  backupDir: './cleanup-backups',
  logFile: './cleanup-log.txt'
}

// Files to remove (deprecated)
const DEPRECATED_FILES = [
  'api/schemas.ts',
  'utils/validation.ts', 
  'hooks/useFormValidation.ts',
  'features/stores/components/StoreList/StoreList.tsx'
]

// Directories to remove (deprecated)
const DEPRECATED_DIRS = [
  'features/stores/components/StoreList'
]

// Import replacements
const IMPORT_REPLACEMENTS = [
  {
    from: /from ["']\.\.\/\.\.\/api\/backend-types["']/g,
    to: "from '@api/types'"
  },
  {
    from: /from ["']\.\.\/\.\.\/types\/sdk-augmentations["']/g,
    to: "from '@api/types'"
  },
  {
    from: /from ["']\.\.\/api\/backend-types["']/g,
    to: "from '@api/types'"
  },
  {
    from: /from ["']\.\.\/types\/sdk-augmentations["']/g,
    to: "from '@api/types'"
  },
  {
    from: /from ["']@\/api\/backend-types["']/g,
    to: "from '@api/types'"
  },
  {
    from: /from ["']@\/types\/sdk-augmentations["']/g,
    to: "from '@api/types'"
  }
]

// Console log replacements
const CONSOLE_REPLACEMENTS = [
  {
    from: /console\.log\(/g,
    to: 'logger.info('
  },
  {
    from: /console\.warn\(/g,
    to: 'logger.warn('
  },
  {
    from: /console\.error\(/g,
    to: 'logger.error('
  }
]

// ============================================
// Cleanup Operations
// ============================================

class RedundancyCleanup {
  private readonly log: string[] = []

  /**
   * Main cleanup workflow
   */
  async cleanup(): Promise<void> {
    console.log('🧹 Starting redundancy cleanup...')

    try {
      // Step 1: Create backup
      await this.createBackup()

      // Step 2: Remove deprecated files
      await this.removeDeprecatedFiles()

      // Step 3: Update imports
      await this.updateImports()

      // Step 4: Replace console logs
      await this.replaceConsoleLogs()

      // Step 5: Remove unused code
      await this.removeUnusedCode()

      // Step 6: Validate changes
      await this.validateChanges()

      console.log('✅ Cleanup completed successfully!')
      this.logMessage('Cleanup completed successfully')

    } catch (error) {
      console.error('❌ Cleanup failed:', error)
      this.logMessage(`Cleanup failed: ${error}`)
      throw error
    }
  }

  /**
   * Create backup of current state
   */
  private async createBackup(): Promise<void> {
    console.log('📦 Creating backup...')

    const timestamp = new Date().toISOString().replaceAll(/[.:]/g, '-')
    const backupPath = join(CONFIG.backupDir, `backup-${timestamp}`)

    // Create backup directory
    execSync(`mkdir -p ${backupPath}`)

    // Backup entire src directory
    execSync(`cp -r ${CONFIG.srcPath} ${backupPath}/`)

    console.log(`✅ Backup created at ${backupPath}`)
    this.logMessage(`Backup created at ${backupPath}`)
  }

  /**
   * Remove deprecated files and directories
   */
  private async removeDeprecatedFiles(): Promise<void> {
    console.log('🗑️ Removing deprecated files...')

    // Remove deprecated files
    for (const file of DEPRECATED_FILES) {
      const filePath = join(CONFIG.srcPath, file)
      if (existsSync(filePath)) {
        unlinkSync(filePath)
        console.log(`  ✅ Removed ${file}`)
        this.logMessage(`Removed deprecated file: ${file}`)
      }
    }

    // Remove deprecated directories
    for (const dir of DEPRECATED_DIRS) {
      const dirPath = join(CONFIG.srcPath, dir)
      if (existsSync(dirPath)) {
        execSync(`rm -rf ${dirPath}`)
        console.log(`  ✅ Removed directory ${dir}`)
        this.logMessage(`Removed deprecated directory: ${dir}`)
      }
    }
  }

  /**
   * Update imports to use centralized types
   */
  private async updateImports(): Promise<void> {
    console.log('🔄 Updating imports...')

    const files = this.getAllTypeScriptFiles()
    let updatedCount = 0

    for (const file of files) {
      let content = readFileSync(file, 'utf-8')
      let hasChanges = false

      // Apply import replacements
      for (const replacement of IMPORT_REPLACEMENTS) {
        if (replacement.from.test(content)) {
          content = content.replace(replacement.from, replacement.to)
          hasChanges = true
        }
      }

      if (hasChanges) {
        writeFileSync(file, content)
        updatedCount++
        console.log(`  ✅ Updated imports in ${file}`)
        this.logMessage(`Updated imports in: ${file}`)
      }
    }

    console.log(`✅ Updated imports in ${updatedCount} files`)
  }

  /**
   * Replace console logs with proper logging
   */
  private async replaceConsoleLogs(): Promise<void> {
    console.log('📝 Replacing console logs...')

    const files = this.getAllTypeScriptFiles()
    let updatedCount = 0

    for (const file of files) {
      let content = readFileSync(file, 'utf-8')
      let hasChanges = false

      // Check if file has console logs
      if (/console\.(log|warn|error)\(/.test(content)) {
        // Add logger import if not present
        if (!content.includes('import { logger }')) {
          const importMatch = /import.*from.*["']@\/utils\/logger["']/.exec(content)
          if (!importMatch) {
            // Add logger import at the top
            const lines = content.split('\n')
            const lastImportIndex = lines.findLastIndex(line => line.startsWith('import'))
            if (lastImportIndex >= 0) {
              lines.splice(lastImportIndex + 1, 0, "import { logger } from '@shared/lib/logger'")
              content = lines.join('\n')
              hasChanges = true
            }
          }
        }

        // Replace console logs
        for (const replacement of CONSOLE_REPLACEMENTS) {
          if (replacement.from.test(content)) {
            content = content.replace(replacement.from, replacement.to)
            hasChanges = true
          }
        }
      }

      if (hasChanges) {
        writeFileSync(file, content)
        updatedCount++
        console.log(`  ✅ Updated console logs in ${file}`)
        this.logMessage(`Updated console logs in: ${file}`)
      }
    }

    console.log(`✅ Updated console logs in ${updatedCount} files`)
  }

  /**
   * Remove unused code
   */
  private async removeUnusedCode(): Promise<void> {
    console.log('🧹 Removing unused code...')

    try {
      // Find unused exports
      const result = execSync('npx ts-unused-exports tsconfig.json --excludePathsFromReport=node_modules', { 
        encoding: 'utf-8',
        stdio: 'pipe'
      })

      if (result.trim()) {
        console.log('  📋 Found unused exports:')
        console.log(result)
        this.logMessage(`Found unused exports:\n${result}`)
      }

    } catch {
      console.log('  ⚠️ Could not check for unused exports (ts-unused-exports not available)')
      this.logMessage('Could not check for unused exports')
    }
  }

  /**
   * Validate changes
   */
  private async validateChanges(): Promise<void> {
    console.log('✅ Validating changes...')

    try {
      // Run TypeScript compiler
      execSync('npx tsc --noEmit', { stdio: 'inherit' })
      console.log('  ✅ TypeScript validation passed')

      // Run ESLint
      execSync('npx eslint src --ext .ts,.tsx', { stdio: 'inherit' })
      console.log('  ✅ ESLint validation passed')

    } catch (error) {
      console.error('  ❌ Validation failed:', error)
      this.logMessage(`Validation failed: ${error}`)
      throw error
    }
  }

  /**
   * Get all TypeScript files
   */
  private getAllTypeScriptFiles(): string[] {
    const files: string[] = []

    const scanDir = (dir: string) => {
      const entries = readdirSync(dir, { withFileTypes: true })

      for (const entry of entries) {
        const fullPath = join(dir, entry.name)

        if (entry.isDirectory() && !entry.name.startsWith('.') && entry.name !== 'node_modules') {
          scanDir(fullPath)
        } else if (entry.isFile() && (entry.name.endsWith('.ts') || entry.name.endsWith('.tsx'))) {
          files.push(fullPath)
        }
      }
    }

    scanDir(CONFIG.srcPath)
    return files
  }

  /**
   * Log message
   */
  private logMessage(message: string): void {
    const timestamp = new Date().toISOString()
    this.log.push(`[${timestamp}] ${message}`)
  }

  /**
   * Save log to file
   */
  private saveLog(): void {
    writeFileSync(CONFIG.logFile, this.log.join('\n'))
  }
}

// ============================================
// CLI Interface
// ============================================

async function main() {
  const args = process.argv.slice(2)
  const command = args[0]

  const cleanup = new RedundancyCleanup()

  try {
    switch (command) {
      case 'cleanup': {
        await cleanup.cleanup()
        break
      }

      case 'validate': {
        await cleanup.validateChanges()
        break
      }

      default: {
        console.log('Available commands:')
        console.log('  cleanup  - Remove redundant and legacy code')
        console.log('  validate - Validate current codebase')
        break
      }
    }

  } catch (error) {
    console.error('❌ Command failed:', error)
    process.exit(1)
  }
}

// Run if called directly
if (require.main === module) {
  main()
}

export { RedundancyCleanup }

#!/usr/bin/env tsx
// @ts-nocheck

/**
 * Composition Migration Script
 * 
 * This script automates the migration of existing components to use the new
 * unified composition system. It provides utilities for:
 * 1. Converting page components to use PageCompositionFactory
 * 2. Converting card components to use CardCompositionFactory
 * 3. Converting layout components to use LayoutCompositionFactory
 * 4. Adding composition imports and patterns
 */

import { readFileSync, writeFileSync, existsSync, readdirSync, statSync } from 'node:fs'
import { join, dirname, extname } from 'node:path'
import { execSync } from 'node:child_process'

// ========================================
// Configuration
// ========================================

const CONFIG = {
  srcPath: './src',
  backupDir: './composition-migration-backups',
  logFile: './composition-migration-log.txt',
  fileExtensions: ['.tsx', '.ts'],
  excludePatterns: [
    'node_modules',
    '.git',
    'dist',
    'build',
    'coverage',
    'migration-backups',
    'composition-migration-backups'
  ]
}

// ========================================
// Migration Patterns
// ========================================

const MIGRATION_PATTERNS = {
  // Page composition patterns
  pageComposition: {
    // Marketing pages
    marketingPage: {
      pattern: /<div className="min-h-screen[^>]*>[\S\s]*?<\/div>/g,
      replacement: (match: string) => {
        return match.replace(
          /<div className="min-h-screen[^>]*>/,
          '<PageCompositionFactory.Marketing\n      layout="top-nav"\n      sections={[\'header\', \'content\']}\n      responsive={true}\n      accessibility={true}\n      className="min-h-screen'
        ).replace(
          /<\/div>$/,
          '</PageCompositionFactory.Marketing>'
        )
      }
    },

    // App pages
    appPage: {
      pattern: /<div className={styles\.container}>[\S\s]*?<\/div>/g,
      replacement: (match: string) => {
        return match.replace(
          /<div className={styles\.container}>/,
          '<PageCompositionFactory.App\n      layout="sidebar"\n      sections={[\'header\', \'content\']}\n      responsive={true}\n      accessibility={true}\n      className="min-h-screen bg-gray-50 px-4 md:px-6 py-8"'
        ).replace(
          /<\/div>$/,
          '</PageCompositionFactory.App>'
        )
      }
    }
  },

  // Card composition patterns
  cardComposition: {
    // Basic card
    basicCard: {
      pattern: /<div className="bg-white rounded-lg border[^>]*>[\S\s]*?<\/div>/g,
      replacement: (match: string) => {
        return match.replace(
          /<div className="bg-white rounded-lg border[^>]*>/,
          '<CardCompositionFactory.Custom\n        layout="vertical"\n        size="md"\n        features={{}}\n        responsive={true}\n        interactive={true}'
        ).replace(
          /<\/div>$/,
          '</CardCompositionFactory.Custom>'
        )
      }
    },

    // Product card
    productCard: {
      pattern: /<div className="[^"]*product[^"]*"[^>]*>[\S\s]*?<\/div>/g,
      replacement: (match: string) => {
        return match.replace(
          /<div className="[^"]*product[^"]*"[^>]*>/,
          '<CardCompositionFactory.Product\n        layout="vertical"\n        size="md"\n        features={{\n          image: { aspectRatio: \'4/3\', zoom: true },\n          actions: { primary: { label: \'Add to Cart\' } },\n          meta: { price: { amount: 0 } }\n        }}\n        responsive={true}\n        interactive={true}'
        ).replace(
          /<\/div>$/,
          '</CardCompositionFactory.Product>'
        )
      }
    },

    // Store card
    storeCard: {
      pattern: /<div className="[^"]*store[^"]*"[^>]*>[\S\s]*?<\/div>/g,
      replacement: (match: string) => {
        return match.replace(
          /<div className="[^"]*store[^"]*"[^>]*>/,
          '<CardCompositionFactory.Store\n        layout="vertical"\n        size="lg"\n        features={{\n          image: { aspectRatio: \'16/9\' },\n          actions: { primary: { label: \'View Store\' } },\n          badges: { featured: true },\n          meta: { rating: { value: 0, count: 0 } }\n        }}\n        responsive={true}\n        interactive={true}'
        ).replace(
          /<\/div>$/,
          '</CardCompositionFactory.Store>'
        )
      }
    }
  },

  // Layout composition patterns
  layoutComposition: {
    // Grid layout
    gridLayout: {
      pattern: /<div className="grid[^>]*>[\S\s]*?<\/div>/g,
      replacement: (match: string) => {
        return match.replace(
          /<div className="grid[^>]*>/,
          '<LayoutCompositionFactory.Grid\n        columns={{ mobile: 1, tablet: 2, desktop: 3 }}\n        gap="md"\n        responsive={true}'
        ).replace(
          /<\/div>$/,
          '</LayoutCompositionFactory.Grid>'
        )
      }
    },

    // Flex layout
    flexLayout: {
      pattern: /<div className="flex[^>]*>[\S\s]*?<\/div>/g,
      replacement: (match: string) => {
        return match.replace(
          /<div className="flex[^>]*>/,
          '<LayoutCompositionFactory.Flex\n        direction="row"\n        alignment="start"\n        justify="start"\n        gap="md"\n        responsive={true}'
        ).replace(
          /<\/div>$/,
          '</LayoutCompositionFactory.Flex>'
        )
      }
    },

    // Stack layout
    stackLayout: {
      pattern: /<div className="space-y-[^>]*>[\S\s]*?<\/div>/g,
      replacement: (match: string) => {
        return match.replace(
          /<div className="space-y-[^>]*>/,
          '<LayoutCompositionFactory.Stack\n        direction="column"\n        gap="lg"\n        responsive={true}'
        ).replace(
          /<\/div>$/,
          '</LayoutCompositionFactory.Stack>'
        )
      }
    }
  }
}

// ========================================
// Import Patterns
// ========================================

const IMPORT_PATTERNS = {
  // Page composition imports
  pageComposition: "import { PageCompositionFactory, LayoutCompositionFactory } from '@components/composition'",

  // Card composition imports
  cardComposition: "import { CardCompositionFactory } from '@components/composition'",

  // Layout composition imports
  layoutComposition: "import { LayoutCompositionFactory } from '@components/composition'",

  // Full composition imports
  fullComposition: "import { PageCompositionFactory, CardCompositionFactory, LayoutCompositionFactory } from '@components/composition'"
}

// ========================================
// Migration Functions
// ========================================

class CompositionMigration {
  private readonly logFile: string
  private readonly backupDir: string

  constructor() {
    this.logFile = CONFIG.logFile
    this.backupDir = CONFIG.backupDir
    this.setupDirectories()
  }

  private setupDirectories() {
    if (!existsSync(this.backupDir)) {
      execSync(`mkdir -p "${this.backupDir}"`)
    }
  }

  private log(message: string) {
    const timestamp = new Date().toISOString()
    const logMessage = `[${timestamp}] ${message}\n`
    writeFileSync(this.logFile, logMessage, { flag: 'a' })
    console.log(message)
  }

  private backupFile(filePath: string) {
    const backupPath = join(this.backupDir, filePath)
    const backupDir = dirname(backupPath)

    if (!existsSync(backupDir)) {
      execSync(`mkdir -p "${backupDir}"`)
    }

    const content = readFileSync(filePath, 'utf-8')
    writeFileSync(backupPath, content)
    this.log(`Backed up: ${filePath} -> ${backupPath}`)
  }

  private addCompositionImports(content: string, filePath: string): string {
    // Check if composition imports already exist
    if (content.includes('@components/composition')) {
      return content
    }

    // Determine which imports to add based on file content
    const importsToAdd: string[] = []

    if (content.includes('PageCompositionFactory') || content.includes('PageComposition')) {
      importsToAdd.push('PageCompositionFactory')
    }

    if (content.includes('CardCompositionFactory') || content.includes('CardComposition')) {
      importsToAdd.push('CardCompositionFactory')
    }

    if (content.includes('LayoutCompositionFactory') || content.includes('LayoutComposition')) {
      importsToAdd.push('LayoutCompositionFactory')
    }

    if (importsToAdd.length === 0) {
      return content
    }

    // Add imports after existing imports
    const importStatement = `import { ${importsToAdd.join(', ')} } from '@components/composition'`

    // Find the last import statement
    const importRegex = /^import\s+.*?from\s+["'][^"']+["'];?\s*$/gm
    const imports = content.match(importRegex)

    if (imports && imports.length > 0) {
      const lastImport = imports[imports.length - 1]
      const lastImportIndex = content.lastIndexOf(lastImport)
      const insertIndex = lastImportIndex + lastImport.length

      return content.slice(0, insertIndex) + '\n' + importStatement + '\n' + content.slice(insertIndex)
    } else {
      // No imports found, add at the beginning
      return importStatement + '\n\n' + content
    }
  }

  private migratePageComposition(content: string): string {
    let migratedContent = content

    // Apply page composition patterns
    for (const [patternName, pattern] of Object.entries(MIGRATION_PATTERNS.pageComposition)) {
      migratedContent = migratedContent.replace(pattern.pattern, pattern.replacement)
      if (migratedContent !== content) {
        this.log(`Applied ${patternName} pattern`)
      }
    }

    return migratedContent
  }

  private migrateCardComposition(content: string): string {
    let migratedContent = content

    // Apply card composition patterns
    for (const [patternName, pattern] of Object.entries(MIGRATION_PATTERNS.cardComposition)) {
      migratedContent = migratedContent.replace(pattern.pattern, pattern.replacement)
      if (migratedContent !== content) {
        this.log(`Applied ${patternName} pattern`)
      }
    }

    return migratedContent
  }

  private migrateLayoutComposition(content: string): string {
    let migratedContent = content

    // Apply layout composition patterns
    for (const [patternName, pattern] of Object.entries(MIGRATION_PATTERNS.layoutComposition)) {
      migratedContent = migratedContent.replace(pattern.pattern, pattern.replacement)
      if (migratedContent !== content) {
        this.log(`Applied ${patternName} pattern`)
      }
    }

    return migratedContent
  }

  private migrateFile(filePath: string): boolean {
    try {
      this.log(`Migrating file: ${filePath}`)

      // Backup original file
      this.backupFile(filePath)

      // Read file content
      const content = readFileSync(filePath, 'utf-8')

      // Apply migrations
      let migratedContent = content

      // Add composition imports
      migratedContent = this.addCompositionImports(migratedContent, filePath)

      // Apply page composition patterns
      migratedContent = this.migratePageComposition(migratedContent)

      // Apply card composition patterns
      migratedContent = this.migrateCardComposition(migratedContent)

      // Apply layout composition patterns
      migratedContent = this.migrateLayoutComposition(migratedContent)

      // Write migrated content if changes were made
      if (migratedContent !== content) {
        writeFileSync(filePath, migratedContent)
        this.log(`Successfully migrated: ${filePath}`)
        return true
      } else {
        this.log(`No changes needed: ${filePath}`)
        return false
      }
    } catch (error) {
      this.log(`Error migrating ${filePath}: ${error}`)
      return false
    }
  }

  private getFilesToMigrate(): string[] {
    const files: string[] = []

    const scanDirectory = (dir: string) => {
      const items = readdirSync(dir)

      for (const item of items) {
        const fullPath = join(dir, item)
        const stat = statSync(fullPath)

        if (stat.isDirectory()) {
          // Skip excluded directories
          if (!CONFIG.excludePatterns.some(pattern => fullPath.includes(pattern))) {
            scanDirectory(fullPath)
          }
        } else if (stat.isFile()) {
          // Check if file should be migrated
          const ext = extname(fullPath)
          if (CONFIG.fileExtensions.includes(ext)) {
            files.push(fullPath)
          }
        }
      }
    }

    scanDirectory(CONFIG.srcPath)
    return files
  }

  public async migrateAll(): Promise<void> {
    this.log('Starting composition migration...')

    const files = this.getFilesToMigrate()
    this.log(`Found ${files.length} files to migrate`)

    let migratedCount = 0
    let errorCount = 0

    for (const file of files) {
      try {
        const migrated = this.migrateFile(file)
        if (migrated) {
          migratedCount++
        }
      } catch (error) {
        errorCount++
        this.log(`Error migrating ${file}: ${error}`)
      }
    }

    this.log(`Migration complete!`)
    this.log(`Files migrated: ${migratedCount}`)
    this.log(`Errors: ${errorCount}`)
    this.log(`Total files processed: ${files.length}`)
  }

  public async migrateFile(filePath: string): Promise<void> {
    this.log(`Migrating single file: ${filePath}`)

    if (!existsSync(filePath)) {
      this.log(`File not found: ${filePath}`)
      return
    }

    const migrated = this.migrateFile(filePath)
    if (migrated) {
      this.log(`Successfully migrated: ${filePath}`)
    } else {
      this.log(`No changes needed: ${filePath}`)
    }
  }

  public async migrateDirectory(dirPath: string): Promise<void> {
    this.log(`Migrating directory: ${dirPath}`)

    if (!existsSync(dirPath)) {
      this.log(`Directory not found: ${dirPath}`)
      return
    }

    const files = this.getFilesToMigrate().filter(file => file.startsWith(dirPath))
    this.log(`Found ${files.length} files in directory`)

    let migratedCount = 0

    for (const file of files) {
      try {
        const migrated = this.migrateFile(file)
        if (migrated) {
          migratedCount++
        }
      } catch (error) {
        this.log(`Error migrating ${file}: ${error}`)
      }
    }

    this.log(`Directory migration complete!`)
    this.log(`Files migrated: ${migratedCount}`)
  }
}

// ========================================
// CLI Interface
// ========================================

async function main() {
  const args = process.argv.slice(2)
  const command = args[0]
  const target = args[1]

  const migration = new CompositionMigration()

  switch (command) {
    case 'all': {
      await migration.migrateAll()
      break
    }

    case 'file': {
      if (!target) {
        console.error('Please provide a file path')
        process.exit(1)
      }
      await migration.migrateFile(target)
      break
    }

    case 'directory': {
      if (!target) {
        console.error('Please provide a directory path')
        process.exit(1)
      }
      await migration.migrateDirectory(target)
      break
    }

    default: {
      console.log('Usage:')
      console.log('  tsx scripts/composition-migration.ts all')
      console.log('  tsx scripts/composition-migration.ts file <file-path>')
      console.log('  tsx scripts/composition-migration.ts directory <directory-path>')
      break
    }
  }
}

// Run if called directly
if (require.main === module) {
  main().catch(console.error)
}

export { CompositionMigration }

