import { vi, describe, it, expect, beforeEach } from 'vitest';
import { StoreService } from '../StoreService';
import type { StoreData } from '../LocationService';

// Mock fetch
global.fetch = vi.fn();

describe('StoreService', () => {
  let storeService: StoreService;
  const mockStores: StoreData[] = [
    {
      id: '1',
      name: 'Test Store 1',
      address: '123 Test St',
      latitude: 40.7128,
      longitude: -74.006
    },
    {
      id: '2',
      name: 'Test Store 2',
      address: '456 Test St',
      latitude: 42.3601,
      longitude: -71.0589
    }
  ];

  beforeEach(() => {
    storeService = StoreService.getInstance();
    storeService.clearCache();
    jest.clearAllMocks();
  });

  describe('getAllStores', () => {
    test('fetches stores successfully', async () => {
      (fetch as jest.Mock).mockResolvedValueOnce({
        ok: true,
        json: async () => mockStores
      });

      const result = await storeService.getAllStores();

      expect(result).toEqual(mockStores);
      expect(fetch).toHaveBeenCalledWith('/api/stores');
    });

    test('caches results for subsequent calls', async () => {
      (fetch as jest.Mock).mockResolvedValueOnce({
        ok: true,
        json: async () => mockStores
      });

      // First call
      await storeService.getAllStores();
      // Second call should use cache
      await storeService.getAllStores();

      // Should only call fetch once
      expect(fetch).toHaveBeenCalledTimes(1);
    });

    test('throws error when fetch fails', async () => {
      (fetch as jest.Mock).mockResolvedValueOnce({
        ok: false,
        status: 500
      });

      await expect(storeService.getAllStores()).rejects.toThrow('Failed to fetch stores');
    });

    test('throws error when network fails', async () => {
      (fetch as jest.Mock).mockRejectedValueOnce(new Error('Network error'));

      await expect(storeService.getAllStores()).rejects.toThrow('Network error');
    });
  });

  describe('getStoresByRegion', () => {
    test('fetches stores by region successfully', async () => {
      (fetch as jest.Mock).mockResolvedValueOnce({
        ok: true,
        json: async () => [mockStores[0]]
      });

      const result = await storeService.getStoresByRegion('nyc');

      expect(result).toEqual([mockStores[0]]);
      expect(fetch).toHaveBeenCalledWith('/api/stores?region=nyc');
    });

    test('falls back to getAllStores when region fetch fails', async () => {
      // Region fetch fails
      (fetch as jest.Mock)
        .mockResolvedValueOnce({
          ok: false,
          status: 404
        })
        // Fallback to all stores
        .mockResolvedValueOnce({
          ok: true,
          json: async () => mockStores
        });

      const result = await storeService.getStoresByRegion('unknown');

      expect(result).toEqual(mockStores);
      expect(fetch).toHaveBeenCalledWith('/api/stores?region=unknown');
      expect(fetch).toHaveBeenCalledWith('/api/stores');
    });

    test('caches region-specific results', async () => {
      (fetch as jest.Mock).mockResolvedValueOnce({
        ok: true,
        json: async () => [mockStores[0]]
      });

      // First call
      await storeService.getStoresByRegion('nyc');
      // Second call should use cache
      await storeService.getStoresByRegion('nyc');

      // Should only call fetch once for region
      expect(fetch).toHaveBeenCalledTimes(1);
    });

    test('encodes region parameter correctly', async () => {
      (fetch as jest.Mock).mockResolvedValueOnce({
        ok: true,
        json: async () => []
      });

      await storeService.getStoresByRegion('new york');

      expect(fetch).toHaveBeenCalledWith('/api/stores?region=new%20york');
    });
  });

  describe('caching', () => {
    test('clearCache removes all cached data', async () => {
      (fetch as jest.Mock).mockResolvedValue({
        ok: true,
        json: async () => mockStores
      });

      // Cache some data
      await storeService.getAllStores();
      await storeService.getStoresByRegion('nyc');

      // Clear cache
      storeService.clearCache();

      // Next calls should fetch again
      await storeService.getAllStores();
      await storeService.getStoresByRegion('nyc');

      // Should call fetch twice (once for each after cache clear)
      expect(fetch).toHaveBeenCalledTimes(4);
    });

    test('cache expires after duration', async () => {
      jest.useFakeTimers();

      (fetch as jest.Mock).mockResolvedValue({
        ok: true,
        json: async () => mockStores
      });

      // First call
      await storeService.getAllStores();

      // Fast-forward past cache duration (10 minutes + 1 second)
      jest.advanceTimersByTime(10 * 60 * 1000 + 1000);

      // Second call should fetch again
      await storeService.getAllStores();

      expect(fetch).toHaveBeenCalledTimes(2);

      jest.useRealTimers();
    });
  });

  describe('singleton pattern', () => {
    test('returns same instance', () => {
      const instance1 = StoreService.getInstance();
      const instance2 = StoreService.getInstance();

      expect(instance1).toBe(instance2);
    });
  });
});

/**
 * Geocoding Service - Frontend API client;
 */

export interface GeocodeResult {
  latitude: number;
  longitude: number;
  city?: string;
  state?: string;
  zip?: string;
  country?: string;
  displayName: string;
}

// const API_BASE_URL = import.meta.env.VITE_API_URL || 'http://localhost:3005'

/**
 * Geocode a ZIP code to coordinates;
 */
export async function geocodeZip(zipCode: string): Promise<GeocodeResult | undefined> {
  try {
    const apiBaseUrl = import.meta.env.VITE_API_URL ?? 'http://localhost:3005'
    const url = `${apiBaseUrl}/geocode/zip?zip=${zipCode}`
    console.log(`[Geocoding] Fetching ZIP ${zipCode} from ${url}`)

    const response = await fetch(url)

    if (!response.ok) {
      if (response.status === 404) {
        const errorData = await response.json().catch(() => ({})) as { message?: string }
        console.warn(`[Geocoding] ZIP ${zipCode} not found:`, errorData.message)
        return undefined // ZIP not found;
      }
      const errorText = await response.text().catch(() => 'Unknown error')
      console.error(`[Geocoding] API error (${response.status}):`, errorText)
      throw new Error(`Geocoding failed: ${response.status}`)
    }

    const result = await response.json() as GeocodeResult
    console.log(`[Geocoding] Success for ZIP ${zipCode}:`, result)
    return result;
  } catch (error: unknown) {
    console.error('[Geocoding] Fetch error:', error)
    return undefined;
  }
}

/**
 * Geocode a city/state to coordinates;
 */
export async function geocodeCity(city: string, state: string): Promise<GeocodeResult | undefined> {
  try {
    const apiBaseUrl = import.meta.env.VITE_API_URL ?? 'http://localhost:3005'
    const response = await fetch(
      `${apiBaseUrl}/geocode/city?city=${encodeURIComponent(city)}&state=${state}`
    )

    if (!response.ok) {
      if (response.status === 404) {
        return undefined;
      }
      throw new Error('Geocoding failed')
    }

    return await response.json() as GeocodeResult
  } catch {
    console.error('Geocoding error:')
    return undefined;
  }
}

/**
 * Geocode a full address to coordinates;
 */
export async function geocodeAddress(address: string): Promise<GeocodeResult | undefined> {
  try {
    const apiBaseUrl = import.meta.env.VITE_API_URL ?? 'http://localhost:3005'
    const response = await fetch(
      `${apiBaseUrl}/geocode/address?address=${encodeURIComponent(address)}`
    )

    if (!response.ok) {
      if (response.status === 404) {
        return undefined;
      }
      throw new Error('Geocoding failed')
    }

    return await response.json() as GeocodeResult
  } catch (error: unknown) {
    console.error('Geocoding error:', error)
    return undefined;
  }
}

/**
 * Unified Location Service
 * Consolidates all location functionality with localStorage persistence
 */

import type { LocationData, LocationPreferences, LocationInput } from '@shared/types/types/location.types'

const STORAGE_KEYS = {
  PREFERENCES: 'location_preferences',
  CURRENT_LOCATION: 'current_location',
  LOCATION_HISTORY: 'location_history'
} as const

const MAX_HISTORY_SIZE = 5
const DEFAULT_RADIUS = 25

// OPTIMIZED: Object pool for reducing GC pressure
// class ObjectPool<T> {
//   private readonly pool: T[] = []
//   private readonly createFn: () => T
//   
//   constructor(createFn: () => T, initialSize = 10) {
