/**
 * useAddToCart Hook - Shared cart mutation logic;
 */
import { useMutation, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'
import { handleApiError } from '@api/errors'
import { useCartStore } from '@stores/cartStore'
import type { ItemResponse } from '@api/types'
import { apiClient } from '@api/client'

export interface AddToCartParams {
  storeId: string;
  itemId: string;
  quantity: number;
  title?: string;
  unitPrice?: string | number;
  item?: Partial<ItemResponse>;
}

export function useAddToCart() {
  const queryClient = useQueryClient()
  const addItem = useCartStore((state) => state.addItem)
  const setCart = useCartStore((state) => state.setCart)

  return useMutation({
    mutationFn: async (params: AddToCartParams) => {
      const previousCart = useCartStore.getState().cart
      const optimisticCart = addItem(params)
      try {
        await apiClient.carts().createCart({
          createCartRequest: {
            storeId: params.storeId,
            itemId: params.itemId,
            quantity: params.quantity,
          },
        })
        return optimisticCart
      } catch (error) {
        // Roll back only if this mutation still owns current optimistic state.
        const currentCart = useCartStore.getState().cart
        if (currentCart === optimisticCart) {
          setCart(previousCart)
        }
        throw error
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['cart'] })
      queryClient.invalidateQueries({ queryKey: ['carts'] })
      toast.success('Item added to cart!')
    },
    onError: async (error) => {
      const appError = await handleApiError(error)
      toast.error(appError.message)
    }})
}

/**
 * useAnalytics - Analytics tracking for URL parameter changes;
 */
import { useCallback } from 'react'

export interface AnalyticsEvent {
  action: string;
  category: string;
  label?: string;
  value?: number;
  params?: Record<string, string | number | boolean | undefined>
}

/**
 * Track location search events;
 */
export function useAnalytics() {
  const trackEvent = useCallback((event: AnalyticsEvent) => {
    // Google Analytics 4 (gtag.js)
    if (typeof window !== 'undefined' && 'gtag' in window) {
      const gtag = (window as { gtag?: (...args: unknown[]) => void }).gtag;
      if (gtag) {
        gtag('event', event.action, {
          event_category: event.category,
          event_label: event.label,
          value: event.value,
          ...event.params})
      }
    }

    // Console log in development;
    if (import.meta.env.MODE === 'development') {
      console.log('[Analytics]', event)
    }
  }, [])

  const trackLocationSearch = useCallback((params: {
    latitude?: string;
    longitude?: string;
    city?: string;
    state?: string;
    radius?: string;
  }) => {
    trackEvent({
      action: 'search_location',
      category: 'engagement',
      label: params.city && params.state ? '${params["city"]}, ' + params.state + '' : 'coordinates',
      params: {
        search_latitude: params.latitude,
        search_longitude: params.longitude,
        search_city: params.city,
        search_state: params.state,
        search_radius: params.radius}})
  }, [trackEvent])

  const trackStoreView = useCallback((storeId: string, storeName?: string) => {
    trackEvent({
      action: 'view_store',
      category: 'engagement',
      label: storeName || storeId,
      params: {
        store_id: storeId}})
  }, [trackEvent])

  const trackItemView = useCallback((itemId: string, storeId?: string) => {
    trackEvent({
      action: 'view_item',
      category: 'engagement',
      label: itemId,
      params: {
        item_id: itemId,
        store_id: storeId}})
  }, [trackEvent])

  return {
    trackEvent,
    trackLocationSearch,
    trackStoreView,
    trackItemView}
}

/**
 * useCustomerRealtimeOrder - Real-time order status updates for customers
 * Subscribes to customer's orders and shows live status changes
 */

import { useEffect } from 'react'
import { useQueryClient } from '@tanstack/react-query'
import { getOrderStatusConfig } from '@features/orders/utils/orderUtils'
import { getRealtimeClient } from '@services/realtimeClient'
import { toast } from 'sonner'
import type { OrderStatusChangedEvent } from '@packages/realtime'

export interface UseCustomerRealtimeOrderOptions {
  userId?: string
  orderId?: string
  onStatusChange?: (event: OrderStatusChangedEvent) => void
  enableToast?: boolean
}

const STATUS_MESSAGES: Record<string, string> = {
  PLACED: '📋 Order placed successfully!',
  ACCEPTED: '✅ Your order has been accepted!',
  PREPARING: '👨‍🍳 Your order is being prepared!',
  READY: '🎉 Your order is ready!',
  COMPLETED: '✅ Order completed! Enjoy your meal!',
  CANCELED: '❌ Your order was canceled',
}

export function useCustomerRealtimeOrder(options: UseCustomerRealtimeOrderOptions = {}) {
  const queryClient = useQueryClient()
  const {
    userId,
    orderId,
    onStatusChange,
    enableToast = true,
  } = options

  useEffect(() => {
    const realtimeClient = getRealtimeClient()

    // Connect to WebSocket
    realtimeClient.connect().catch(error => {
      console.error('[Customer Realtime] Connection failed:', error)
    })

    let unsubscribe: (() => void) | undefined

    // Subscribe to customer topic or specific order
    if (orderId) {
      // Subscribe to specific order
      unsubscribe = realtimeClient.subscribeOrder(orderId, (event) => {
        console.log('[Customer Realtime] Order event:', event.type, event.payload)

        if (event.type === 'order.status.changed') {
          const typedEvent = event as OrderStatusChangedEvent
          const payload = typedEvent.payload

          // Optimistically update cached order status immediately.
          queryClient.setQueryData(['order', orderId], (current: any) => {
            if (!current) return current
            return { ...current, status: payload.newStatus }
          })

          // Show toast notification
          if (enableToast) {
            const message = STATUS_MESSAGES[payload.newStatus] || 'Order status: ' + payload.newStatus + ''

            const statusConfig = getOrderStatusConfig(payload.newStatus)
            if (statusConfig.variant === 'success') {
              toast.success(message)
            } else if (statusConfig.variant === 'destructive') {
              toast.error(message)
            } else {
              toast.info(message)
            }
          }

          // Invalidate queries to refresh data
          queryClient.invalidateQueries({ queryKey: ['order', orderId] })
          queryClient.invalidateQueries({ queryKey: ['orders'] })

          // Call custom handler
          if (onStatusChange) {
            onStatusChange(event as OrderStatusChangedEvent)
          }
        }
      })
    } else if (userId) {
      // Subscribe to all customer's orders
      unsubscribe = realtimeClient.subscribeCustomer(userId, (event) => {
        console.log('[Customer Realtime] Customer event:', event.type, event.payload)

        if (event.type === 'order.status.changed') {
          const typedEvent = event as OrderStatusChangedEvent
          const payload = typedEvent.payload

          // Optimistically update the specific order in cache if present.
          queryClient.setQueryData(['order', payload.orderId], (current: any) => {
            if (!current) return current
            return { ...current, status: payload.newStatus }
          })

          // Show toast
          if (enableToast) {
            const message = STATUS_MESSAGES[payload.newStatus] || 'Order updated: ' + payload.newStatus + ''
            toast.info(message)
          }

          // Refresh queries
          queryClient.invalidateQueries({ queryKey: ['order', payload.orderId] })
          queryClient.invalidateQueries({ queryKey: ['orders'] })

          // Call handler
          if (onStatusChange) {
            onStatusChange(event as OrderStatusChangedEvent)
          }
        }
      })
    }

    return () => {
      if (unsubscribe) {
        unsubscribe()
      }
    }
  }, [userId, orderId, queryClient, onStatusChange, enableToast])

  return {
    isConnected: () => getRealtimeClient().isConnected(),
  }
}

/**
 * useFormValidation Hook - Simplified form validation with Zod
 * Supports full form and field-level validation
 * DEPRECATED: Use unified validation service instead
 * @deprecated Use @utils/validation/unified for new code
 */
import { useState, useCallback } from 'react'
import type { ZodSchema } from 'zod'
// import { validationService, type ValidationResult } from '@shared/lib/validation/unified' // Removed due to missing export

export function useFormValidation<T extends Record<string, unknown>>(schema?: ZodSchema<T>) {
  const [errors, setErrors] = useState<Partial<Record<keyof T, string>>>({})

  /**
   * Validate entire form
   */
  const validate = useCallback((data: T): boolean => {
    if (!schema) return true

    const result = schema.safeParse(data)

    if (result.success) {
      setErrors({})
      return true
    }

    // Extract errors from Zod
    const newErrors: Partial<Record<keyof T, string>> = {}
    for (const err of result.error.errors) {
      const field = err.path[0] as keyof T
      if (field) {
        newErrors[field] = err.message
      }
    }

    setErrors(newErrors)
    return false
  }, [schema])

  /**
   * Clear all errors
   */
  const clearErrors = useCallback(() => {
    setErrors({})
  }, [])

  /**
   * Set error for a specific field
   */
  const setFieldError = useCallback((field: keyof T, message: string) => {
    // @ts-expect-error - Complex generic constraint, works at runtime
    setErrors(prev => {
      if (!message) {
        // eslint-disable-next-line @typescript-eslint/no-unused-vars
        const { [field]: removed, ...rest } = prev
        return rest
      }
      return { ...prev, [field]: message }
    })
  }, [])

  /**
   * Clear error for a specific field
   */
  const clearFieldError = useCallback((field: keyof T) => {
    // @ts-expect-error - Complex generic constraint, works at runtime
    setErrors(prev => {
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { [field]: removed, ...rest } = prev
      return rest
    })
  }, [])

  /**
   * Validate a single field with safe schema access
   * Only works with basic z.object() schemas
   * For refined/effect schemas, validation happens on full form submit
   */
  const validateField = useCallback((field: keyof T, value: unknown): boolean => {
    if (!schema) return true

    // Try to get field schema (only works with z.object schemas)
    const fieldSchema = (schema as { shape?: Record<string, unknown> })?.shape?.[field as string]

    if (!fieldSchema) {
      // Can't do field-level validation on refined/effect schemas
      // Validation will happen on form submit instead
      return true
    }

    // Validate individual field
    const result = (fieldSchema as any)?.safeParse?.(value)
    if (result.success) {
      clearFieldError(field)
      return true
    }

    const firstError = result.error.errors[0]
    if (firstError) {
      setFieldError(field, firstError.message)
    }
    return false
  }, [schema, setFieldError, clearFieldError])

  return { 
    errors, 
    validate, 
    validateField,
    clearErrors, 
    setFieldError,
    clearFieldError,
  }
}

