   */
  coordinates: (lat: number, lng: number) => {
    const result = locationValidator.validateCoordinates(lat, lng)
    return result.valid ? undefined : result.error || 'Invalid coordinates'
  }
} as const

/**
 * useMapData - Ultra-high performance map data processing
 * Single Responsibility: Minimize loops, reduce memory allocations, optimize data flow
 */
import { useMemo, useRef } from 'react'
import type { StoreWithDistance } from '@api/types'
import type { LocationData, LocationCoordinates } from '@shared/types'
import { hasValidCoordinates } from '@shared/lib/utils/storeAccessors'
import { processStoresOptimized } from '@shared/lib/utils/performance/optimized-loops'

export interface MapData {
  validStores: StoreWithDistance[]
  storeLocations: LocationCoordinates[]
  nearestStore: StoreWithDistance | undefined
  mapCenter: [number, number]
  mapZoom: number
  minDistance: number
  maxDistance: number
  totalStores: number
  validStoresCount: number
}

export interface MapDataOptions {
  stores: StoreWithDistance[]
  userLocation?: LocationData
  radiusMiles?: number
  defaultCenter?: [number, number]
  defaultZoom?: number
}

/**
 * Optimized map data hook with single-pass processing
 * Replaces multiple loops with one efficient pass
 */
export function useMapData({
  stores,
  userLocation,
  radiusMiles = 25,
  defaultCenter = [40.7505, -73.9934],
  defaultZoom = 12
}: MapDataOptions): MapData {
  // Use ref to maintain stable reference and avoid unnecessary recalculations
  const lastProcessedStores = useRef<StoreWithDistance[]>([])
  const lastProcessedUserLocation = useRef<LocationData | undefined>(undefined)

  return useMemo(() => {
    // Early return if data hasn't changed
    if (stores === lastProcessedStores.current && userLocation === lastProcessedUserLocation.current) {
      return {
        validStores: [],
        storeLocations: [],
        nearestStore: undefined,
        mapCenter: defaultCenter,
        mapZoom: defaultZoom,
        minDistance: 0,
        maxDistance: 0,
        totalStores: 0,
        validStoresCount: 0
      }
    }

    // Update refs
    lastProcessedStores.current = stores
    lastProcessedUserLocation.current = userLocation

    // Single-pass processing using optimized utility
    const processed = processStoresOptimized(stores, {
      findNearest: true,
      filterValid: true,
      sortByDistance: true
    })

    // Calculate map center efficiently
    let mapCenter: [number, number]
    if (userLocation) {
      mapCenter = [userLocation.latitude, userLocation.longitude]
    } else if (processed.storeLocations.length > 0 && processed.storeLocations[0]) {
      // Use first store location (already sorted by distance)
      mapCenter = [processed.storeLocations[0].latitude, processed.storeLocations[0].longitude]
    } else {
      mapCenter = defaultCenter
    }

    // Optimized zoom calculation using lookup table
    const zoomLookup = [
      { maxRadius: 5, zoom: 13 },
      { maxRadius: 25, zoom: 11 },
      { maxRadius: 50, zoom: 10 },
      { maxRadius: 100, zoom: 9 },
      { maxRadius: Infinity, zoom: 7 }
    ]

    let mapZoom = defaultZoom
    for (const entry of zoomLookup) {
      if (radiusMiles <= entry.maxRadius) {
        mapZoom = entry.zoom
        break
      }
    }

    return {
      validStores: processed.validStores,
      storeLocations: processed.storeLocations,
      nearestStore: processed.nearestStore,
      mapCenter,
      mapZoom,
      minDistance: processed.minDistance,
      maxDistance: processed.maxDistance,
      totalStores: stores.length,
      validStoresCount: processed.validStores.length
    }
  }, [stores, userLocation, radiusMiles, defaultCenter, defaultZoom])
}

/**
 * Optimized marker processing hook
 * Batch operations for better DOM performance
 */
export function useOptimizedMarkers(
  stores: StoreWithDistance[],
  options: {
    batchSize?: number
    findNearest?: boolean
  } = {}
) {
  return useMemo(() => {
    const { batchSize = 50, findNearest = true } = options

    const markerData: {
      store: StoreWithDistance
      isNearest: boolean
      position: [number, number]
      distance?: number
    }[] = []

    let nearestStore: StoreWithDistance | undefined
    let minDistance = Infinity

    // Process in batches for better performance
    for (let i = 0; i < stores.length; i += batchSize) {
      const batch = stores.slice(i, i + batchSize)

      for (const store of batch) {

        if (!hasValidCoordinates(store)) continue

        // Find nearest in same pass
        let isNearest = false
        if (findNearest && store.distance !== undefined && store.distance < minDistance) {
          minDistance = store.distance
          nearestStore = store
          isNearest = true
        }

        markerData.push({
          store,
          isNearest,
          position: [Number(store.latitude), Number(store.longitude)],
          distance: store.distance
        })
      }
    }

    return { markerData, nearestStore }
  }, [stores, options.batchSize, options.findNearest])
}

/**
 * usePaginatedList - Common handler for paginated, filtered, searchable lists
 * Combines pagination + filtering + search in one reusable hook
 */
import { useMemo } from 'react'
import { usePagination } from './usePagination'

export interface UsePaginatedListOptions<T> {
  /** Array of items to paginate */
  items: T[]
  /** Items per page (default: 20) */
  pageSize?: number
  /** Initial page (default: 1) */
  initialPage?: number
  /** Search query string */
  searchQuery?: string
  /** Fields to search in (array of field names) */
  searchFields?: (keyof T)[]
  /** Custom search function (overrides searchFields) */
  searchFn?: (item: T, query: string) => boolean
  /** Active filters object */
  filters?: Record<string, unknown>
  /** Custom filter function */
  filterFn?: (item: T, filters: Record<string, unknown>) => boolean
  /** Sort function */
  sortFn?: (a: T, b: T) => number
}

export interface PaginatedListResult<T> {
  /** Current page of items (filtered, searched, sorted) */
  items: T[]
  /** All filtered items (before pagination) */
  allFilteredItems: T[]
  /** Pagination controls */
  pagination: {
    currentPage: number
    totalPages: number
    totalItems: number
    pageSize: number
    goToPage: (page: number) => void
    nextPage: () => void
    previousPage: () => void
    setPageSize: (size: number) => void
    hasNextPage: boolean
    hasPreviousPage: boolean
  }
  /** Item counts */
  counts: {
    total: number
    filtered: number
    displayed: number
  }
}

/**
 * Unified hook for paginated lists with search and filtering
 * 
 * Features:
 * - Client-side pagination
 * - Search across multiple fields
 * - Custom filtering
 * - Sorting
 * - Memoized for performance
 * 
 * @example
 * ```tsx
 * const { items, pagination, counts } = usePaginatedList({
 *   items: orders,
 *   pageSize: 20,
 *   searchQuery,
 *   searchFields: ['id', 'user.name'],
 *   filters: { status: 'ACTIVE' },
 *   filterFn: (order, filters) => filters.status === 'ALL' || order.status === filters.status,
 *   sortFn: (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
 * })
 * 
 * return (
 *   <>
 *     {items.map(item => <Item key={item.id} data={item} />)}
 *     <Pagination {...pagination} />
 *   </>
 * )
 * ```
 */
export function usePaginatedList<T extends Record<string, any>>({
  items,
  pageSize = 20,
  initialPage = 1,
  searchQuery = '',
  searchFields = [],
  searchFn,
  filters = {},
  filterFn,
  sortFn,
}: UsePaginatedListOptions<T>): PaginatedListResult<T> {
  // Apply search
  const searchedItems = useMemo(() => {
    if (!searchQuery) return items

    // Use custom search function if provided
    if (searchFn) {
      return items.filter((item) => searchFn(item, searchQuery))
    }

    // Use searchFields if provided
    if (searchFields.length > 0) {
      const query = searchQuery.toLowerCase()
      return items.filter((item) => {
        return searchFields.some((field) => {
          const value = getNestedValue(item, field as string)
          return value?.toString().toLowerCase().includes(query)
        })
      })
    }

    // Default: search all string fields
    const query = searchQuery.toLowerCase()
    return items.filter((item) => {
      return Object.values(item).some((value) => {
        if (typeof value === 'string') {
          return value.toLowerCase().includes(query)
        }
        return false
      })
    })
  }, [items, searchQuery, searchFields, searchFn])

  // Apply filters
  const filteredItems = useMemo(() => {
    if (!filterFn || Object.keys(filters).length === 0) {
      return searchedItems
    }

    return searchedItems.filter((item) => filterFn(item, filters))
  }, [searchedItems, filters, filterFn])

  // Apply sorting
  const sortedItems = useMemo(() => {
    if (!sortFn) return filteredItems

    return [...filteredItems].sort(sortFn)
  }, [filteredItems, sortFn])

  // Apply pagination
  const pagination = usePagination(sortedItems, {
    pageSize,
    initialPage,
  })

  // Calculate counts
  const counts = useMemo(() => ({
    total: items.length,
    filtered: sortedItems.length,
    displayed: pagination.currentItems.length,
  }), [items.length, sortedItems.length, pagination.currentItems.length])

  return {
    items: pagination.currentItems,
    allFilteredItems: sortedItems,
    pagination: {
      currentPage: pagination.currentPage,
      totalPages: pagination.totalPages,
      totalItems: sortedItems.length,
      pageSize: pagination.pageSize,
      goToPage: pagination.goToPage,
      nextPage: pagination.nextPage,
      previousPage: pagination.previousPage,
      setPageSize: pagination.setPageSize,
      hasNextPage: pagination.hasNextPage,
      hasPreviousPage: pagination.hasPreviousPage,
    },
    counts,
  }
}

/**
 * Helper to get nested object values
 * Supports dot notation: 'user.name', 'order.store.name'
 */
function getNestedValue(obj: Record<string, unknown>, path: string): unknown {
  return path.split('.').reduce((current: unknown, key: string) => {
    if (current && typeof current === 'object' && key in current) {
      return (current as Record<string, unknown>)[key]
    }
    return
  }, obj)
}

