// @ts-nocheck
/**
 * Standardized Error Handling for SDK Hooks
 * 
 * Provides consistent error handling patterns across all hooks:
 * 1. Centralized error processing
 * 2. User-friendly error messages
 * 3. Error categorization and logging
 * 4. Retry strategies
 * 5. Error boundary integration
 */

import { handleApiError, type AppError } from '@api/errors'
import { toast } from 'sonner'

// ============================================
// Error Categories
// ============================================

export enum ErrorCategory {
  NETWORK = 'network',
  VALIDATION = 'validation',
  AUTHENTICATION = 'authentication',
  AUTHORIZATION = 'authorization',
  NOT_FOUND = 'not_found',
  SERVER = 'server',
  UNKNOWN = 'unknown'
}

export interface CategorizedError extends AppError {
  category: ErrorCategory
  userMessage: string
  shouldRetry: boolean
  retryAfter?: number
}

// ============================================
// Error Processing
// ============================================

/**
 * Process and categorize API errors
 */
export async function processApiError(error: unknown): Promise<CategorizedError> {
  const appError = await handleApiError(error)

  // Categorize error based on status code and message
  const category = categorizeError(appError)
  const userMessage = getUserFriendlyMessage(appError, category)
  const shouldRetry = shouldRetryError(appError, category)
  const retryAfter = getRetryDelay(appError, category)

  return {
    ...appError,
    category,
    userMessage,
    shouldRetry,
    retryAfter
  }
}

/**
 * Categorize error based on status code and content
 */
function categorizeError(error: AppError): ErrorCategory {
  const status = error.status || 0
  const message = error.message?.toLowerCase() || ''

  // Network errors
  if (status === 0 || status >= 500) {
    return ErrorCategory.NETWORK
  }

  // Authentication errors
  if (status === 401 || message.includes('unauthorized') || message.includes('token')) {
    return ErrorCategory.AUTHENTICATION
  }

  // Authorization errors
  if (status === 403 || message.includes('forbidden') || message.includes('permission')) {
    return ErrorCategory.AUTHORIZATION
  }

  // Not found errors
  if (status === 404 || message.includes('not found')) {
    return ErrorCategory.NOT_FOUND
  }

  // Validation errors
  if (status === 400 || message.includes('validation') || message.includes('invalid')) {
    return ErrorCategory.VALIDATION
  }

  // Server errors
  if (status >= 500) {
    return ErrorCategory.SERVER
  }

  return ErrorCategory.UNKNOWN
}

/**
 * Get user-friendly error message
 */
function getUserFriendlyMessage(error: AppError, category: ErrorCategory): string {
  const messages: Record<ErrorCategory, string> = {
    [ErrorCategory.NETWORK]: 'Network connection issue. Please check your internet connection and try again.',
    [ErrorCategory.VALIDATION]: 'Please check your input and try again.',
    [ErrorCategory.AUTHENTICATION]: 'Please log in to continue.',
    [ErrorCategory.AUTHORIZATION]: 'You don\'t have permission to perform this action.',
    [ErrorCategory.NOT_FOUND]: 'The requested item could not be found.',
    [ErrorCategory.SERVER]: 'Server error. Please try again later.',
    [ErrorCategory.UNKNOWN]: 'An unexpected error occurred. Please try again.'
  }

  // Use specific error message if available and user-friendly
  if (error.message && isUserFriendlyMessage(error.message)) {
    return error.message
  }

  return messages[category]
}

/**
 * Check if error message is user-friendly
 */
function isUserFriendlyMessage(message: string): boolean {
  const technicalTerms = [
    'internal server error',
    'unexpected token',
    'syntax error',
    'reference error',
    'type error',
    'network error',
    'timeout',
    'cors',
    'csp',
    'xss'
  ]

  return !technicalTerms.some(term => message.toLowerCase().includes(term))
}

/**
 * Determine if error should be retried
 */
function shouldRetryError(error: AppError, category: ErrorCategory): boolean {
  // Don't retry client errors (4xx) except network issues
  if (error.status && error.status >= 400 && error.status < 500) {
    return category === ErrorCategory.NETWORK
  }

  // Retry server errors and network issues
  return category === ErrorCategory.SERVER || category === ErrorCategory.NETWORK
}

/**
 * Get retry delay in milliseconds
 */
function getRetryDelay(error: AppError, category: ErrorCategory): number | undefined {
  if (!shouldRetryError(error, category)) {
    return undefined
  }

  // Exponential backoff based on error type
  const baseDelay = category === ErrorCategory.NETWORK ? 1000 : 2000
  const maxDelay = 30_000 // 30 seconds max

  // Use retry-after header if available
  if (error.retryAfter) {
    return Math.min(error.retryAfter * 1000, maxDelay)
  }

  return Math.min(baseDelay, maxDelay)
}

// ============================================
// Error Handling Hooks
// ============================================

/**
 * useErrorHandler - Hook for consistent error handling
 */
export function useErrorHandler() {
  const handleError = (error: CategorizedError, options?: {
    showToast?: boolean
    logError?: boolean
    onRetry?: () => void
  }) => {
    const { showToast = true, logError = true, onRetry } = options || {}

    // Log error for debugging
    if (logError) {
      console.error(`[${error.category.toUpperCase()}] ${error.message}`, {
        status: error.status,
        category: error.category,
        shouldRetry: error.shouldRetry,
        retryAfter: error.retryAfter
      })
    }

    // Show user-friendly message
    if (showToast) {
      toast.error(error.userMessage, {
        duration: error.category === ErrorCategory.NETWORK ? 5000 : 3000,
        action: error.shouldRetry && onRetry ? {
          label: 'Retry',
          onClick: onRetry
        } : undefined
      })
    }

    // Handle specific error categories
    switch (error.category) {
      case ErrorCategory.AUTHENTICATION: {
        // Trigger logout flow
        window.dispatchEvent(new CustomEvent('auth:logout'))
        break
      }

      case ErrorCategory.NETWORK: {
        // Could trigger network status monitoring
        break
      }

      default: {
        // No special handling needed
        break
      }
    }
  }

  return { handleError }
}

// ============================================
// Query/Mutation Error Handling
// ============================================

/**
 * Standard error handler for useQuery
 */
export function createQueryErrorHandler() {
  return async (error: unknown) => {
    throw await processApiError(error)
  }
}

/**
 * Standard error handler for useMutation
 */
export function createMutationErrorHandler() {
  return async (error: unknown) => {
    throw await processApiError(error)
  }
}

/**
 * Standard onError handler for mutations
 */
export function createMutationOnError() {
  const { handleError } = useErrorHandler()

  return (error: CategorizedError) => {
    handleError(error, {
      showToast: true,
      logError: true
    })
  }
}

// ============================================
// Retry Strategies
// ============================================

/**
 * Standard retry configuration for queries
 */
export const queryRetryConfig = {
  retry: (failureCount: number, error: unknown): boolean => {
    // Don't retry on client errors (4xx)
    if (error && typeof error === 'object' && 'status' in error && 
        typeof error.status === 'number' && error.status >= 400 && error.status < 500) {
      return false
    }

    // Retry up to 3 times for server errors
    return failureCount < 3
  },
  retryDelay: (attemptIndex: number) => Math.min(1000 * 2 ** attemptIndex, 30_000)
}

/**
 * Standard retry configuration for mutations
 */
export const mutationRetryConfig = {
  retry: (failureCount: number, error: unknown): boolean => {
    // Only retry network errors for mutations
    return failureCount < 2 && error && typeof error === 'object' && 
           'category' in error && error.category === ErrorCategory.NETWORK
  },
  retryDelay: (attemptIndex: number) => Math.min(1000 * 2 ** attemptIndex, 10_000)
}

/**
 * URL Location Utilities
 * 
 * Extracted utility functions for URL location processing
 */

import { locationValidator } from '@shared/lib/utils/validation/unified'
import type { LocationData } from '@shared/types'

// Re-export LocationData for use in other modules


// ========================================
// Location Comparison Utilities
// ========================================

export function isSameLocation(a: LocationData | undefined, b: LocationData | undefined): boolean {
  if (!a || !b) return a === b
  return (
    a.latitude === b.latitude &&
    a.longitude === b.longitude &&
    a.radiusMiles === b.radiusMiles &&
    a.city === b.city &&
    a.state === b.state &&
    a.zip === b.zip &&
    a.source === b.source
  )
}

// ========================================
// Display Name Utilities
// ========================================

export function buildDisplayName(params: {
  city?: string
  state?: string
  zip?: string
}): string {
  const parts: string[] = []
  if (params.city) parts.push(params.city)
  if (params.state && locationValidator.validateState(params.state).valid) parts.push(params.state)
  if (params.zip && locationValidator.validateZipCode(params.zip).valid) parts.push(params.zip)
  return parts.length > 0 ? parts.join(', ') : 'Your Location'
}

// ========================================
// Coordinate Processing Utilities
// ========================================

export function processCoordinateParams(params: {
  latitude?: string
  longitude?: string
  radiusMiles?: string
  city?: string
  state?: string
  zip?: string
}): { valid: boolean; location?: LocationData; error?: string } {
  if (!params.latitude || !params.longitude) {
    return { valid: false, error: 'Coordinates required' }
  }

  const validation = locationValidator.validateCoordinates(
    params.latitude,
    params.longitude,
    params.radiusMiles
  )

  if (!validation.valid || !validation.data) {
    return { valid: false, error: validation.error }
  }

  // Validate and sanitize optional fields
  const cityResult = params.city ? locationValidator.sanitizeCityName(params.city) : { valid: false, data: undefined }
  const city = cityResult.valid ? cityResult.data : undefined
  const stateResult = params.state ? locationValidator.validateState(params.state) : { valid: false, data: undefined }
  const state = stateResult.valid ? stateResult.data : undefined
  const zipResult = params.zip ? locationValidator.validateZipCode(params.zip) : { valid: false, data: undefined }
  const zip = zipResult.valid ? zipResult.data : undefined

  const location: LocationData = {
    latitude: validation.data.latitude,
    longitude: validation.data.longitude,
    radiusMiles: validation.data.radius,
    displayName: buildDisplayName(params),
    source: 'search' as const,
    city,
    state,
    zip,
  }

  return { valid: true, location }
}

// ========================================
// City/State Processing Utilities
// ========================================

export function processCityStateParams(params: {
  city?: string
  state?: string
  radiusMiles?: string
}): { valid: boolean; location?: LocationData; error?: string } {
  if (!params.city || !params.state) {
    return { valid: false, error: 'City and state required' }
  }

  const cityResult = locationValidator.sanitizeCityName(params.city)
  const city = cityResult.valid ? cityResult.data : undefined
  const stateResult = locationValidator.validateState(params.state)
  const state = stateResult.valid ? stateResult.data : undefined

  if (!city || !state) {
    return { valid: false, error: 'Invalid city or state' }
  }

  const location: LocationData = {
    latitude: 0, // Will be geocoded
    longitude: 0, // Will be geocoded
    radiusMiles: params.radiusMiles ? Number.parseFloat(params.radiusMiles) : 25,
    displayName: buildDisplayName(params),
    source: 'search' as const,
    city,
    state,
    zip: undefined,
  }

  return { valid: true, location }
}

// ========================================
// ZIP Processing Utilities
// ========================================

export function processZipParams(params: {
  zip?: string
  radiusMiles?: string
}): { valid: boolean; location?: LocationData; error?: string } {
  if (!params.zip) {
    return { valid: false, error: 'ZIP code required' }
  }

  if (!locationValidator.validateZipCode(params.zip).valid) {
    return { valid: false, error: 'Invalid ZIP code' }
  }

  // For ZIP 94102 (San Francisco), use known coordinates
  // This is a temporary solution until full geocoding is implemented
  if (params.zip === '94102') {
    const radius = params.radiusMiles ? Number.parseFloat(params.radiusMiles) : 25

    const location: LocationData = {
      latitude: 37.7749,
      longitude: -122.4194,
      radiusMiles: radius,
      displayName: 'San Francisco, CA (' + params.zip + ')',
      source: 'search' as const,
      city: 'San Francisco',
      state: 'CA',
      zip: params.zip,
    }

    return { valid: true, location }
  }

  return { valid: false, error: 'ZIP code not supported yet' }
}

// ========================================
// URL Parameter Type Detection
// ========================================

export type UrlParamType = 'coordinates' | 'cityState' | 'zip' | 'none'

export function detectUrlParamType(params: {
  latitude?: string
  longitude?: string
  city?: string
  state?: string
  zip?: string
}): UrlParamType {
  if (params.latitude && params.longitude) {
    return 'coordinates'
  }
  if (params.city && params.state) {
    return 'cityState'
  }
  if (params.zip) {
    return 'zip'
  }
  return 'none'
}

// ========================================
// Main Processing Function
// ========================================

export function processUrlParams(params: {
  latitude?: string
  longitude?: string
  radiusMiles?: string
  city?: string
  state?: string
  zip?: string
}): { valid: boolean; location?: LocationData; error?: string } {
  const paramType = detectUrlParamType(params)

  switch (paramType) {
    case 'coordinates': {
      return processCoordinateParams(params)
    }
    case 'cityState': {
      return processCityStateParams(params)
    }
    case 'zip': {
      return processZipParams(params)
    }
    default: {
      return { valid: false, error: 'No valid location parameters found' }
    }
  }
}

export {type LocationData} from '@shared/types'

/**
 * useDeleteConfirm - Reusable delete with confirmation;
 */
import { useMutation, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'
import { handleApiError } from '@api/errors'

export interface UseDeleteConfirmOptions {
  entityName: string;
  invalidateQueries: string[]
  deleteFn: (id: string) => Promise<void>
}

export function useDeleteConfirm({
  entityName,
  invalidateQueries,
  deleteFn}: UseDeleteConfirmOptions) {
  const queryClient = useQueryClient()

  const deleteMutation = useMutation({
    mutationFn: deleteFn,
    onSuccess: () => {
      for (const queryKey of invalidateQueries) {
        queryClient.invalidateQueries({ queryKey: [queryKey] })
      }
      toast.success('' + entityName + ' deleted successfully!')
    },
    onError: async (error) => {
      const appError = await handleApiError(error)
      toast.error(appError.message)
    }})

  const confirmDelete = (id: string, name: string) => {
    if (window.confirm('Are you sure you want to delete "' + name + '"?')) {
      deleteMutation.mutate(id)
    }
  }

  return {
    confirmDelete,
    isDeleting: deleteMutation.isPending}
}

