/**
 * useMediaList - Fetch media for a store or item
 */
import { useQuery } from '@tanstack/react-query'
import type { MediaApiResponse } from '@api/types'

interface UseMediaListParams {
  storeId?: string;
  itemId?: string;
}

export function useMediaList({ storeId, itemId }: UseMediaListParams) {
  return useQuery<MediaApiResponse[]>({
    queryKey: ['media', 'list', { storeId, itemId }],
    queryFn: async (): Promise<MediaApiResponse[]> => {
      const token = localStorage.getItem('token')
      const apiUrl = import.meta.env.VITE_API_URL || 'http://localhost:3005'

      const url = new URL(apiUrl + '/media')
      if (storeId) url.searchParams.set('storeId', storeId)
      if (itemId) url.searchParams.set('itemId', itemId)

      const response = await fetch(url.toString(), {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json',
          ...(token ? { Authorization: 'Bearer ' + token + '' } : {}),
        },
      })

      if (!response.ok) {
        const error = await response.json().catch(() => ({}))
        throw new Error(error.error || 'Failed to load media')
      }

      const payload = await response.json() as { data?: any[] }
      const list = Array.isArray(payload?.data) ? payload.data : []

      return list.map((m: any) => {
        const meta = (m?.metadata ?? {})
        return {
          id: String(m.id),
          url: String(m.url),
          kind: (m.kind as MediaApiResponse['kind']) ?? 'IMAGE',
          filename: String(meta.originalFilename ?? meta.key ?? 'media'),
          size: Number(meta.size ?? m.size ?? 0),
          mimeType: String(meta.mimetype ?? 'application/octet-stream'),
          createdAt: String(m.createdAt ?? ''),
          updatedAt: String(m.updatedAt ?? ''),
          thumbnail: m.thumbnail ?? undefined,
          altText: m.altText ?? undefined,
          sortIndex: typeof m.sortIndex === 'number' ? m.sortIndex : undefined,
          storeId: m.storeId ?? undefined,
          itemId: m.itemId ?? undefined,
        } satisfies MediaApiResponse
      })
    },
    enabled: !!(storeId || itemId)
  })
}

/**
 * useMediaUpload - Upload media files for stores or items;
 */
import { useMutation, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'
import type { MediaApiResponse } from '@api/types'

interface UploadMediaInput {
  file: File;
  storeId?: string;
  itemId?: string;
  altText?: string;
  sortIndex?: number;
}

export function useMediaUpload() {
  const queryClient = useQueryClient()

  return useMutation<MediaApiResponse, Error, UploadMediaInput>({
    mutationFn: async (input: UploadMediaInput) => {
      const formData = new FormData()
      formData.append('file', input.file)

      if (input.storeId) {
        formData.append('storeId', input.storeId)
      }

      if (input.itemId) {
        formData.append('itemId', input.itemId)
      }

      if (input.altText) {
        formData.append('altText', input.altText)
      }

      if (input.sortIndex !== undefined) {
        formData.append('sortIndex', input.sortIndex.toString())
      }

      // Upload via fetch since SDK doesn't handle multipart/form-data well;
      const token = localStorage.getItem('token')
      const apiUrl = import.meta.env.VITE_API_URL || 'http://localhost:3005'

      const response = await fetch('' + apiUrl + '/media/upload', {
        method: 'POST',
        headers: {
          ...(token ? { Authorization: 'Bearer ' + token + '' } : {})},
        body: formData})

      if (!response.ok) {
        const error = await response.json()
        throw new Error(error.error || 'Upload failed')
      }

      return response.json()
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: ['media', 'list'] })
      toast.success('Media uploaded successfully')
    },
    onError: (error) => {
      toast.error((error as any) instanceof Error && error !== undefined ? error.message : 'Upload failed')
    }})
}

