  return (
    <div className={sidebarClasses}>
      {sidebarPosition === 'left' && (
        <aside className="sidebar-composition-sidebar" style={sidebarStyle}>
          {sidebar}
        </aside>
      )}

      <main className="sidebar-composition-content">
