      </main>

      {sidebarPosition === 'right' && (
        <aside className="sidebar-composition-sidebar" style={sidebarStyle}>
          {sidebar}
        </aside>
      )}
    </div>
  )
})

SidebarCompositionComponent.displayName = 'SidebarComposition'

