 * ConfirmDialog - Proper friction for critical actions
 * Replaces window.confirm() with emotional, controlled experience
 */
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from '../Dialog'
import { Button } from '../Button'
import { useState, useCallback } from 'react'

export interface ConfirmDialogProps {
  open: boolean
  onOpenChange: (open: boolean) => void
  title: string
  description: string
  confirmLabel?: string
  cancelLabel?: string
  variant?: 'danger' | 'default'
  onConfirm: () => void | Promise<void>
  isLoading?: boolean
}

/**
 * Modal confirmation with intentional friction
 * - Visual pause before action
 * - Clear consequence description
 * - Prominent danger styling for destructive actions
 */
export function ConfirmDialog({
  open,
  onOpenChange,
  title,
  description,
  confirmLabel = 'Confirm',
  cancelLabel = 'Cancel',
  variant = 'default',
  onConfirm,
  isLoading = false
}: ConfirmDialogProps) {
  const confirmVariantMap = {
    danger: 'danger',
    default: 'primary'
  } as const
  const confirmVariant = confirmVariantMap[variant]

  const handleConfirm = async () => {
    await onConfirm()
    onOpenChange(false)
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[425px]">
        <DialogHeader>
          <DialogTitle className="text-xl font-semibold">
            {title}
          </DialogTitle>
          <DialogDescription className="text-sm text-muted-foreground pt-2">
            {description}
          </DialogDescription>
        </DialogHeader>

        <DialogFooter className="gap-2 sm:gap-0">
          <Button
            variant="outline"
            onClick={() => onOpenChange(false)}
            disabled={isLoading}
          >
            {cancelLabel}
          </Button>
          <Button
            variant={confirmVariant}
            onClick={handleConfirm}
            isLoading={isLoading}
          >
            {confirmLabel}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

/**
 * Hook for easy confirmation dialogs
 * Usage:
 *   const confirm = useConfirm()
 *   await confirm({ title: 'Delete?', description: '...' })
 */
export function useConfirm() {
  const [state, setState] = useState<{
    open: boolean
    resolve: ((value: boolean) => void) | undefined
    props: Omit<ConfirmDialogProps, 'open' | 'onOpenChange' | 'onConfirm'> | undefined
  }>({
    open: false,
    resolve: undefined,
    props: undefined
  })

  const confirm = useCallback((props: Omit<ConfirmDialogProps, 'open' | 'onOpenChange' | 'onConfirm'>) => {
    return new Promise<boolean>((resolve) => {
      setState({
        open: true,
        resolve,
        props
      })
    })
  }, [])

  const handleConfirm = useCallback(() => {
    state.resolve?.(true)
    setState({ open: false, resolve: undefined, props: undefined })
  }, [state.resolve])

  const handleCancel = useCallback(() => {
    state.resolve?.(false)
    setState({ open: false, resolve: undefined, props: undefined })
  }, [state.resolve])

  const dialog = state.props ? (
    <ConfirmDialog
      {...state.props}
      open={state.open}
      onOpenChange={(open) => !open && handleCancel()}
      onConfirm={handleConfirm}
    />
  ) : undefined

  return { confirm, dialog }
}

import type { ReactNode } from 'react'
import { SkeletonList } from '../Skeleton'
import { Button } from '../Button'
import { AlertCircle, Inbox } from 'lucide-react'

/**
 * DataState - Modern data state handler with Tailwind
 * Declarative loading/error/empty states
 */

export interface DataStateProps<T> {
  data: T[] | undefined  
  isLoading: boolean
  error: Error | undefined  
  children: (data: T[]) => ReactNode
  emptyMessage?: string
  errorMessage?: string
  loadingMessage?: string
  skeletonCount?: number
  onRetry?: () => void
}

export function DataState<T>({
  data,
  isLoading,
  error,
  children,
  emptyMessage = 'No items found',
  errorMessage,
  loadingMessage = 'Loading...',
  skeletonCount = 3,
  onRetry,
}: DataStateProps<T>) {
  // Loading state
  if (isLoading) {
    return (
      <div className="space-y-4">
        {loadingMessage && (
          <p className="text-muted-foreground text-center">{loadingMessage}</p>
        )}
        <SkeletonList count={skeletonCount} />
      </div>
    )
  }

  // Error state
  if (error) {
    return (
      <div className="flex flex-col items-center justify-center py-12 px-4 text-center">
        <AlertCircle className="h-12 w-12 text-destructive mb-4" />
        <h3 className="text-lg font-semibold mb-2">Something went wrong</h3>
        <p className="text-muted-foreground mb-4">
          {errorMessage || error.message}
        </p>
        {onRetry && (
          <Button onClick={onRetry} variant="outline">
            Try Again
          </Button>
        )}
      </div>
    )
  }

  // Empty state
  if (!data || data.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-12 px-4 text-center">
        <Inbox className="h-12 w-12 text-muted-foreground mb-4" />
        <p className="text-muted-foreground">{emptyMessage}</p>
      </div>
    )
  }

  // Success state
  return <>{children(data)}</>
}

import React, { type ReactNode } from 'react'
import { type LucideIcon, Inbox } from 'lucide-react'
import { cn } from '@shared/lib/cn'

/**
 * EmptyState — Unified empty/zero-state component.
 * Supports both the legacy API (message + action object) and the
 * newer API (description + action as ReactNode) for backward compat.
 */

export interface EmptyStateProps {
  title?: string
  /** Legacy prop name — alias for description */
  message?: string
  description?: string
  /** Lucide icon component (preferred) or arbitrary ReactNode */
  icon?: LucideIcon | ReactNode
  /** ReactNode action (new) or legacy { label, onClick } object */
  action?: ReactNode | { label: string; onClick: () => void }
  className?: string
}

export function EmptyState({
  title,
  message,
  description,
  icon: IconProp,
  action,
  className,
}: EmptyStateProps) {
  const displayText = description || message

  // Resolve icon — either a Lucide component or raw ReactNode
  const renderIcon = () => {
    if (!IconProp) return <Inbox className="h-10 w-10 text-muted-foreground/40" strokeWidth={1.5} />
    if (React.isValidElement(IconProp)) return IconProp

    // Lucide exports are often forwardRef objects (not plain functions), so treat "object" as a component type.
    if (typeof IconProp === 'function' || typeof IconProp === 'object') {
      const Icon = IconProp as LucideIcon
      return React.createElement(Icon, { className: 'h-10 w-10 text-muted-foreground/40', strokeWidth: 1.5 })
    }

    return null
  }

  // Resolve action — either ReactNode or legacy { label, onClick }
  const renderAction = () => {
    if (!action) return null
    if (React.isValidElement(action)) return action
    if (typeof action === 'object' && 'label' in (action as any) && 'onClick' in (action as any)) {
      const legacy = action as { label: string; onClick: () => void }
      return (
        <button
          onClick={legacy.onClick}
          className="inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md font-medium min-h-[44px] px-4 py-2 text-base bg-primary text-primary-foreground hover:bg-primary/90 transition-all active:scale-[0.98]"
        >
          {legacy.label}
        </button>
      )
    }
    // Non-element objects are not valid React children.
    if (typeof action === 'object') return null
    return action
  }

  return (
    <div className={cn(
      'flex flex-col items-center justify-center py-16 px-6 text-center rounded-xl border border-dashed border-border bg-card',
      className
    )}>
      <div className="mb-4">{renderIcon()}</div>

      {title && (
        <h3 className="text-lg font-semibold tracking-tight mb-1">{title}</h3>
      )}

      {displayText && (
        <p className="text-sm text-muted-foreground mb-6 max-w-xs leading-relaxed">
          {displayText}
        </p>
      )}

      {renderAction()}
    </div>
  )
}

