/**
 * ErrorState - Modern error state with Tailwind;
 */

export interface ErrorStateProps {
  title?: string;
  message: string;
  error?: Error;
  onRetry?: () => void;
  className?: string;
}

export function ErrorState({ 
  title = 'Something went wrong', 
  message, 
  error,
  onRetry, 
  className
}: ErrorStateProps) {
  return (
    <div className={cn(
      'flex flex-col items-center justify-center py-12 px-4 text-center',
      className
    )}>
      <AlertCircle className="h-12 w-12 text-destructive mb-4" />
      
      <h3 className="text-lg font-semibold mb-2">{title}</h3>
      
      <p className="text-muted-foreground mb-2 max-w-sm">
        {message}
      </p>

      {error && (
        <p className="text-sm text-destructive/80 mb-6 font-mono max-w-md">
          {error.message}
        </p>
      )}
      
      {onRetry && (
        <Button onClick={onRetry} variant="outline">
          Try Again
        </Button>
      )}
    </div>
  )
}

/**
 * FormField Component - Simplified field wrapper with auto-error from context;
 * Works with Form component (auto-errors) or standalone (manual errors)
 */
import type { ReactNode} from 'react';
import { useCallback } from 'react'
import { Input, type InputProps } from '../Input'
import { useFormContext } from '../Form/FormContextUtils'

export interface FormFieldProps extends Omit<InputProps, 'label'> {
  /** Field name/identifier */
  name: string;
  /** Field label */
  label: string;
  /** Validation error message (optional, auto-fetched from Form context if available) */
  error?: string;
  /** Helper text displayed below field */
  helperText?: string;
  /** Custom input component (defaults to Input) */
  children?: ReactNode;
  /** Validate on blur (default: true if in Form context) */
  validateOnBlur?: boolean;
  /** Validate on change (default: false) */
  validateOnChange?: boolean;
}

/**
 * Extract correct value from input based on type;
 */
function extractInputValue(target: HTMLInputElement): string | number | boolean | undefined {
  if (target.type === 'checkbox') {
    return target.checked;
  }
  
  if (target.type === 'radio') {
    return target.checked ? target.value : undefined;
  }
  
  if (target.type === 'number') {
    const num = target.valueAsNumber;
    // Return undefined for empty/invalid numbers (allows clearing field)
    return Number.isNaN(num) ? undefined : num;
  }
  
  return target.value;
}

/**
 * FormField - Wraps input with label, error, and helper text;
 * Automatically gets errors from Form context when used inside Form;
 * 
 * @example;
 * ```tsx;
 * // Inside Form - auto error handling;
 * <Form schema={schema} data={data} onSubmit={handler}>
 *   <FormField name="email" label="Email" type="email" />
 * </Form>
 * 
 * // Standalone - manual error handling;
 * <FormField;
 *   name="email"
 *   label="Email"
 *   error={errors['email']}
 *   helperText="We'll never share your email"
 * />
 * ```
 */
export function FormField({
  name,
  label,
  error: propError,
  helperText,
  children,
  validateOnBlur = true,
  validateOnChange = false,
  onChange,
  onBlur,
  ...inputProps
}: FormFieldProps) {
  const formContext = useFormContext()

  // Use prop error if provided, otherwise get from context;
  const error = propError ?? formContext?.errors[name]
  
  // Get form state from context;
  const isSubmitting = formContext?.isSubmitting ?? false;
  // Handle blur validation with proper value extraction;
  const handleBlur = useCallback((e: React.FocusEvent<HTMLInputElement>) => {
    onBlur?.(e)

    if (validateOnBlur && formContext?.validateField) {
      const value = extractInputValue(e.target)
      formContext.validateField(name, value)
    }
  }, [onBlur, validateOnBlur, formContext, name])

  // Handle change validation with proper value extraction;
  const handleChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    onChange?.(e)

    if (validateOnChange && formContext?.validateField) {
      const value = extractInputValue(e.target)
      formContext.validateField(name, value)
    }
  }, [onChange, validateOnChange, formContext, name])

  // Custom children render (with error display)
  if (children) {
    return (
      <div className="">
        <div className="">
          <label htmlFor={name} className="">
            {label}
            {inputProps.required && <span className="">*</span>}
          </label>
          {children}
        </div>
        
        {helperText && !error && (
          <p className="">{helperText}</p>
        )}
        
        {error && (
          <p className="" role="alert">
            {error}
          </p>
        )}
      </div>
    )
  }

  // Default Input render (Input handles its own error/helper display)
  return (
    <div className="">
      <Input
        id={name}
        name={name}
        label={label}
        error={error}
        helperText={helperText}
        disabled={isSubmitting || inputProps.disabled}
        onChange={handleChange}
        onBlur={handleBlur}
        {...inputProps}
      />
    </div>
  )
}

/**
 * Form Component - Simplified form wrapper with validation
 * Handles submission, validation, error state, and form state tracking
 */
import type { FormEvent, ReactNode} from 'react';
import { useState, useCallback, useMemo, useRef } from 'react'
import type { ZodSchema } from 'zod'
import { useFormValidation } from '@shared/hooks/useFormValidation'
import { Alert } from '../Alert'
import { FormProvider } from './FormContext'

export interface FormProps<T extends Record<string, unknown>> {
  /** Zod schema for validation */
  schema?: ZodSchema<T>
  /** Form submission handler */
  onSubmit: (data: T) => void | Promise<void>
  /** Success callback after successful submission */
  onSuccess?: () => void
  /** Error callback if submission fails */
  onError?: (error: Error) => void
  /** Form data object */
  data: T
  /** Child elements (FormField components) */
  children: ReactNode
  /** Error message from API or other sources */
  error?: string | undefined
  /** Loading state during submission */
  isLoading?: boolean
  /** Validate on field change (default: false) */
  validateOnChange?: boolean
  /** Validate on field blur (default: true) */
  validateOnBlur?: boolean
  /** Disable all form fields */
  disabled?: boolean
  /** Additional CSS classes */
  className?: string
}

/**
 * Shallow comparison for object equality
 */
function shallowEqual<T extends Record<string, unknown>>(obj1: T, obj2: T): boolean {
  const keys = Object.keys(obj1) as (keyof T)[]
  if (keys.length !== Object.keys(obj2).length) return false
  return keys.every(key => obj1[key] === obj2[key])
}

/**
 * Optimized Form component with context-based error sharing
 * 
 * @example
 * ```tsx
 * const [formData, setFormData] = useState({ email: '', password: '' })
 * 
 * <Form
 *   schema={loginSchema}
 *   data={formData}
 *   onSubmit={handleLogin}
 *   onSuccess={() => navigate('/dashboard')}
 *   validateOnBlur
 * >
 *   <FormField name="email" label="Email" type="email" />
 *   <FormField name="password" label="Password" type="password" />
 *   <Button type="submit">Login</Button>
 * </Form>
 * ```
 */
export function Form<T extends Record<string, unknown>>({
  schema,
  onSubmit,
  onSuccess,
  onError,
  data,
  children,
  error,
  isLoading = false,
  validateOnChange: _validateOnChange = false,
  validateOnBlur: _validateOnBlur = true,
  disabled = false,
  className = '',
}: FormProps<T>) {
  // Always call hooks unconditionally (can't be conditional)
  const validation = useFormValidation(schema)
  const [isSubmitting, setIsSubmitting] = useState(false)
  const initialDataRef = useRef(data)

  // Track if form has been modified (optimized with shallow comparison)
  const isDirty = useMemo(() => {
    return !shallowEqual(data, initialDataRef.current)
  }, [data])

  // Check if form is valid (no errors)
  const isValid = useMemo(() => {
    if (!schema || !validation) return true
    return Object.keys(validation.errors).length === 0
  }, [schema, validation])

  const handleSubmit = async (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault()

    // Prevent double-submit
    if (isSubmitting) return

    // Validate if schema provided
    if (schema && validation && !validation.validate(data)) {
      return
    }

    setIsSubmitting(true)

    try {
      await onSubmit(data)
      onSuccess?.()
    } catch (error_) {
      const error = error_ instanceof Error ? error_ : new Error('Submission failed')
      onError?.(error)
    } finally {
      setIsSubmitting(false)
    }
  }

  // Reset form to initial state (stable reference)
  const reset = useCallback(() => {
    // Reset errors if validation is available
    if (schema) {
      validation?.clearErrors()
    }
  }, [schema, validation])

  // Context value for FormField (optimized dependencies)
  const contextValue = useMemo(() => ({
    errors: (validation?.errors || {}) as Record<string, string>,
    isSubmitting: isSubmitting || isLoading || disabled,
    isDirty,
    isValid,
    validateField: validation?.validateField,
    reset,
  }), [
    validation?.errors,
    validation?.validateField,
    isSubmitting,
    isLoading,
    disabled,
    isDirty,
    isValid,
    reset,
  ])

  return (
    <FormProvider value={contextValue}>
      <form
        onSubmit={handleSubmit}
        className={` ${className || ''}`}
        noValidate
      >
        {error && (
          <Alert variant="error" className="">
            {error}
          </Alert>
        )}
        {children}
      </form>
    </FormProvider>
  )
}

/**
 * Image Component
 * Global image component with skeleton loading, fallback handling, and lazy loading
 * Performance: Native lazy loading, memoized colors, optimized rendering
 */
import type { ImgHTMLAttributes } from 'react'
import { useMemo, memo } from 'react'
import { useImageLoader } from '@shared/hooks/useImageLoader'
import { generateColorFromSeed } from '@shared/lib/colorGenerator'

export interface ImageProps extends ImgHTMLAttributes<HTMLImageElement> {
  src: string
  alt: string
  fallbackSeed?: string | undefined
  containerClassName?: string | undefined
  aspectRatio?: string | undefined
}

function ImageComponent({
  src,
  alt,
  fallbackSeed = src,
  className = '',
  containerClassName = '',
  aspectRatio,
  loading: loadingProp = 'lazy', // Default to lazy loading
  ...props
}: ImageProps) {
  const { loading, error, handleLoad, handleError } = useImageLoader(src)
  const fallbackColor = useMemo(
    () => generateColorFromSeed(fallbackSeed),
    [fallbackSeed]
  )

  const containerStyle = useMemo(
    () => aspectRatio ? { aspectRatio } : undefined,
    [aspectRatio]
  )

  const imageClassNames = useMemo(() => [
    'object-cover w-full h-full',
    loading && 'opacity-0',
    className,
  ]
    .filter(Boolean)
    .join(' '), [loading, className])

  if (error) {
    return (
      <div
        className={'relative overflow-hidden ' + containerClassName + ''}
        style={{ ...containerStyle, backgroundColor: fallbackColor }}
      >
        <div className="flex items-center justify-center text-muted-foreground" role="img" aria-label={alt}>
          {alt}
        </div>
      </div>
    )
  }

  return (
    <div className={'relative overflow-hidden ' + containerClassName + ''} style={containerStyle}>
      {loading && <div className="absolute inset-0 bg-muted animate-pulse" />}
      <img
        src={src}
        alt={alt}
        className={imageClassNames}
        loading={loadingProp} // Native lazy loading
        decoding="async" // Asynchronous image decoding
        onLoad={handleLoad}
        onError={handleError}
        {...props}
      />
    </div>
  )
}

// Memoize to prevent unnecessary re-renders
export const Image = memo(ImageComponent)

