// @ts-nocheck
/**
 * Unified Error States System
 * 
 * Provides consistent error handling patterns across the entire application.
 * Replaces multiple error implementations with a single, unified system.
 * 
 * Features:
 * - Consistent error severity levels
 * - Multiple error display variants
 * - Unified retry mechanisms
 * - Accessibility support
 * - Performance optimized
 */

import React, { memo } from 'react'
import { AlertCircle, XCircle, AlertTriangle, Info, RefreshCw, X } from 'lucide-react'
import { Button } from '../Button'
import { cn } from '@shared/lib/cn'

// ========================================
// Types & Interfaces
// ========================================

export type ErrorSeverity = 'low' | 'medium' | 'high' | 'critical'
export type ErrorVariant = 'inline' | 'banner' | 'modal' | 'page' | 'toast'
export type ErrorSize = 'sm' | 'md' | 'lg'

export interface ErrorConfig {
  severity?: ErrorSeverity
  variant?: ErrorVariant
  size?: ErrorSize
  title?: string
  message: string
  details?: string
  showRetry?: boolean
  showDetails?: boolean
  showClose?: boolean
  onRetry?: () => void
  onClose?: () => void
  onShowDetails?: () => void
  className?: string
}

// ========================================
// Error Configuration
// ========================================

const severityConfig: Record<ErrorSeverity, {
  icon: React.ComponentType<{ className?: string }>
  color: string
  bgColor: string
  borderColor: string
  textColor: string
}> = {
  low: {
    icon: Info,
    color: 'text-blue-600',
    bgColor: 'bg-blue-50',
    borderColor: 'border-blue-200',
    textColor: 'text-blue-800'
  },
  medium: {
    icon: AlertCircle,
    color: 'text-yellow-600',
    bgColor: 'bg-yellow-50',
    borderColor: 'border-yellow-200',
    textColor: 'text-yellow-800'
  },
  high: {
    icon: AlertTriangle,
    color: 'text-orange-600',
    bgColor: 'bg-orange-50',
    borderColor: 'border-orange-200',
    textColor: 'text-orange-800'
  },
  critical: {
    icon: XCircle,
    color: 'text-red-600',
    bgColor: 'bg-red-50',
    borderColor: 'border-red-200',
    textColor: 'text-red-800'
  }
}

const sizeConfig: Record<ErrorSize, {
  icon: string
  title: string
  message: string
  padding: string
  spacing: string
}> = {
  sm: {
    icon: 'h-4 w-4',
    title: 'text-sm font-medium',
    message: 'text-xs',
    padding: 'p-3',
    spacing: 'gap-2'
  },
  md: {
    icon: 'h-5 w-5',
    title: 'text-base font-semibold',
    message: 'text-sm',
    padding: 'p-4',
    spacing: 'gap-3'
  },
  lg: {
    icon: 'h-6 w-6',
    title: 'text-lg font-semibold',
    message: 'text-base',
    padding: 'p-6',
    spacing: 'gap-4'
  }
}

// ========================================
// Error Components
// ========================================

/**
 * Inline Error - For forms, inputs, small areas
 */
export const InlineError = memo<ErrorConfig>(({ 
  severity = 'medium',
  size = 'sm',
  title,
  message,
  details,
  showDetails = false,
  onShowDetails,
  className 
}) => {
  const config = severityConfig[severity]
  const sizeStyles = sizeConfig[size]
  const Icon = config.icon

  return (
    <div className={cn(
      'flex items-start',
      sizeStyles.spacing,
      className
    )}>
      <Icon className={cn(config.icon, config.color, sizeStyles.icon)} />
      <div className="flex-1 min-w-0">
        {title && (
          <p className={cn(sizeStyles.title, config.textColor)}>{title}</p>
        )}
        <p className={cn(sizeStyles.message, config.textColor)}>{message}</p>
        {details && showDetails && (
          <details className="mt-2">
            <summary className="cursor-pointer text-xs text-muted-foreground hover:text-foreground">
              Show details
            </summary>
            <pre className="mt-2 text-xs text-muted-foreground whitespace-pre-wrap">
              {details}
            </pre>
          </details>
        )}
        {details && !showDetails && onShowDetails && (
          <button
            onClick={onShowDetails}
            className="mt-1 text-xs text-muted-foreground hover:text-foreground underline"
          >
            Show details
          </button>
        )}
      </div>
    </div>
  )
})

/**
 * Banner Error - For top of page, important notifications
 */
export const BannerError = memo<ErrorConfig>(({ 
  severity = 'high',
  size = 'md',
  title = 'Something went wrong',
  message,
  details,
  showRetry = true,
  showClose = true,
  onRetry,
  onClose,
  className 
}) => {
  const config = severityConfig[severity]
  const sizeStyles = sizeConfig[size]
  const Icon = config.icon

  return (
    <div className={cn(
      'flex items-start border-l-4',
      config.bgColor,
      config.borderColor,
      sizeStyles.padding,
      sizeStyles.spacing,
      className
    )}>
      <Icon className={cn(config.icon, config.color, sizeStyles.icon, 'flex-shrink-0 mt-0.5')} />
      <div className="flex-1 min-w-0">
        <h3 className={cn(sizeStyles.title, config.textColor)}>{title}</h3>
        <p className={cn(sizeStyles.message, config.textColor, 'mt-1')}>{message}</p>
        {details && (
          <details className="mt-2">
            <summary className="cursor-pointer text-sm text-muted-foreground hover:text-foreground">
              Show details
            </summary>
            <pre className="mt-2 text-sm text-muted-foreground whitespace-pre-wrap">
              {details}
            </pre>
          </details>
        )}
        {showRetry && onRetry && (
          <div className="mt-3">
            <Button
              size="small"
              variant="outline"
              onClick={onRetry}
              className="mr-3"
            >
              <RefreshCw className="h-4 w-4 mr-2" />
              Try Again
            </Button>
          </div>
        )}
      </div>
      {showClose && onClose && (
        <button
          onClick={onClose}
          className="flex-shrink-0 p-1 rounded-md hover:bg-black/5 transition-colors"
          aria-label="Close error"
        >
          <X className="h-4 w-4" />
        </button>
      )}
    </div>
  )
})

/**
 * Modal Error - For overlay dialogs
 */
export const ModalError = memo<ErrorConfig>(({ 
  severity = 'critical',
  size = 'lg',
  title = 'Error',
  message,
  details,
  showRetry = true,
  showClose = true,
  onRetry,
  onClose,
  className 
}) => {
  const config = severityConfig[severity]
